    try{q("INSERT IGNORE INTO branches(id,name,code,city,address,phone,is_main,is_active,created_by,created_at) VALUES(1,'الفرع الرئيسي','MAIN','','','',1,1,1,NOW())");}catch(Throwable $e){}
    try{foreach(['accounts','customers','employees','banks','cashboxes','visa_batches','visa_professions','visa_authorizations','transactions','office_transfers','vouchers','voucher_lines','journal_entries','journal_lines','ledger_entries','refunds','delivery_receipts','employee_entitlements'] as $t){q("UPDATE `$t` SET branch_id=1 WHERE branch_id IS NULL OR branch_id=0");}}catch(Throwable $e){}
