    try{q('UPDATE refunds r JOIN transactions t ON t.id=r.transaction_id SET r.branch_id=t.branch_id WHERE r.branch_id IS NULL OR r.branch_id=0');}catch(Throwable $e){}
    try{q('UPDATE visa_professions p JOIN visa_batches b ON b.id=p.batch_id SET p.branch_id=b.branch_id WHERE p.branch_id IS NULL OR p.branch_id=0');}catch(Throwable $e){}
