    if(count($out)<2)$miss[]='سطرين على الأقل';
    if($deSide<1||$crSide<1)$miss[]='يجب وجود طرف مدين وطرف دائن';
    if(abs($de-$cr)>0.01)$miss[]='القيد غير متوازن حسب عملة المراجعة';
    if(empty($miss)){foreach($byCur as $cid=>$bc){$diff=round(($bc['d']??0)-($bc['c']??0),2);if(abs($diff)>0.01){$acc=currency_clearing_account_v52($branchId);$out[]=['account_id'=>$acc,'debit'=>$diff<0?abs($diff):0,'credit'=>$diff>0?$diff:0,'currency_id'=>(int)$cid,'target_currency_id'=>(int)$cid,'exchange_rate'=>1,'description'=>'تسوية تلقائية لفروق العملات داخل القيد'];}}}
    return ['ok'=>empty($miss),'errors'=>$miss,'lines'=>$out,'debit'=>$de,'credit'=>$cr];
}
function create_journal_with_lines($entryNo,$type,$desc,$reviewCur,$lines,$branchId=null,$entryDate=null){
    $branchId=(int)($branchId?:branch_id());$reviewCur=(int)($reviewCur?:1);$entryDate=$entryDate?:date('Y-m-d');
    assert_accounting_open_v53($entryDate,'إنشاء قيد آلي',$branchId);
    $check=normalize_journal_lines_v52($lines,$reviewCur,$branchId);
    if(!$check['ok'])throw new RuntimeException('لا يمكن إنشاء القيد: '.implode('، ',$check['errors']));
    $started=tx_start_v52();
    try{
        $dt=$entryDate;$tm=date('H:i:s');
        q('INSERT INTO journal_entries(entry_no,entry_date,entry_time,journal_type,description,review_currency_id,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,?,NOW(),?)',[$entryNo,$dt,$tm,$type,$desc,$reviewCur,user()['id']??0,$branchId]);
        $jid=db()->lastInsertId();
        foreach($check['lines'] as $ln){
            $aid=(int)$ln['account_id'];$de=(float)$ln['debit'];$cr=(float)$ln['credit'];$cur=(int)$ln['currency_id'];$target=(int)$ln['target_currency_id'];$rate=(float)$ln['exchange_rate'];$amount=$de>0?$de:$cr;$result=fx_convert($amount,$cur,$target,$rate);$ldesc=$ln['description']?:$desc;
            q('INSERT INTO journal_lines(journal_id,account_id,debit,credit,currency_id,target_currency_id,exchange_rate,result_amount,description,branch_id) VALUES(?,?,?,?,?,?,?,?,?,?)',[$jid,$aid,$de,$cr,$cur,$target,$rate,$result,$ldesc,$branchId]);
            ledger_branch($branchId,$aid,'journal',$jid,$ldesc,$de,$cr,$cur,amount_to_review_v52(1,$cur,$reviewCur,$target,$rate),$entryDate);
        }
        tx_commit_v52($started);return $jid;
    }catch(Throwable $e){tx_rollback_v52($started);throw $e;}
}

function add_account($type,$name,$nature='debit',$cur=1){$bid=function_exists('branch_id')?(int)branch_id():1;$hasBranch=branch_col_exists_v41('accounts','branch_id'); if($hasBranch){$r=q('SELECT id FROM accounts WHERE name=? AND type=? AND branch_id=? LIMIT 1',[$name,$type,$bid])->fetch();}else{$r=q('SELECT id FROM accounts WHERE name=? AND type=? LIMIT 1',[$name,$type])->fetch();} if($r)return $r['id']; $group=['عميل'=>'عملاء المركز الرئيسي','وكيل'=>'وكلاء المركز الرئيسي','مورد'=>'موردين المركز الرئيسي','موظف'=>'موظفين المركز الرئيسي','بنك'=>'بنوك المركز الرئيسي','صندوق'=>'صناديق المركز الرئيسي','مكتب مخلص'=>'مكاتب مخلصة المركز الرئيسي'][$type]??null; $parent=null; $prefix='9'; if($group){$parent=q('SELECT id FROM accounts WHERE name=? LIMIT 1',[$group])->fetchColumn()?:null; $prefix=q('SELECT account_no FROM accounts WHERE id=?',[$parent])->fetchColumn()?:'9';} $cnt=q('SELECT COUNT(*) FROM accounts WHERE parent_id '.($parent?'=?':'IS NULL'),$parent?[$parent]:[])->fetchColumn(); $no=$prefix.str_pad((string)(((int)$cnt)+1),3,'0',STR_PAD_LEFT); if($hasBranch){q('INSERT INTO accounts(account_no,name,type,nature,currency_id,parent_id,branch_id,created_at) VALUES(?,?,?,?,?,?,?,NOW())',[$no,$name,$type,$nature,$cur,$parent,$bid]);}else{q('INSERT INTO accounts(account_no,name,type,nature,currency_id,parent_id,created_at) VALUES(?,?,?,?,?,?,NOW())',[$no,$name,$type,$nature,$cur,$parent]);} return db()->lastInsertId();}
function add_account_for_branch_v49($branchId,$type,$name,$nature='debit',$cur=1){
    $branchId=(int)($branchId?:1);$name=trim((string)$name);if($name==='')$name=$type.' فرع '.$branchId;
    $hasBranch=branch_col_exists_v41('accounts','branch_id');
    if($hasBranch){$r=q('SELECT id FROM accounts WHERE name=? AND type=? AND branch_id=? LIMIT 1',[$name,$type,$branchId])->fetch();}else{$r=q('SELECT id FROM accounts WHERE name=? AND type=? LIMIT 1',[$name,$type])->fetch();}
    if($r)return (int)$r['id'];
    $group=['عميل'=>'عملاء المركز الرئيسي','وكيل'=>'وكلاء المركز الرئيسي','مورد'=>'موردين المركز الرئيسي','موظف'=>'موظفين المركز الرئيسي','بنك'=>'بنوك المركز الرئيسي','صندوق'=>'صناديق المركز الرئيسي','مكتب مخلص'=>'مكاتب مخلصة المركز الرئيسي'][$type]??null;
    $parent=null;$prefix='9';
    if($group){$parent=q('SELECT id FROM accounts WHERE name=? LIMIT 1',[$group])->fetchColumn()?:null;$prefix=$parent?(q('SELECT account_no FROM accounts WHERE id=?',[$parent])->fetchColumn()?:'9'):'9';}
    $cnt=(int)q('SELECT COUNT(*) FROM accounts WHERE parent_id '.($parent?'=?':'IS NULL'),$parent?[$parent]:[])->fetchColumn();
    do{$no=$prefix.str_pad((string)(++$cnt),3,'0',STR_PAD_LEFT);$exists=q('SELECT id FROM accounts WHERE account_no=? LIMIT 1',[$no])->fetchColumn();}while($exists);
    if($hasBranch){q('INSERT INTO accounts(account_no,name,type,nature,currency_id,parent_id,branch_id,created_at) VALUES(?,?,?,?,?,?,?,NOW())',[$no,$name,$type,$nature,$cur,$parent,$branchId]);}
    else{q('INSERT INTO accounts(account_no,name,type,nature,currency_id,parent_id,created_at) VALUES(?,?,?,?,?,?,NOW())',[$no,$name,$type,$nature,$cur,$parent]);}
    return (int)db()->lastInsertId();
}
