function ledger($account_id,$src,$srcid,$desc,$debit=0,$credit=0,$cur=1,$rate=1,$entryDate=null){$entryDate=$entryDate?:date('Y-m-d');assert_accounting_open_v53($entryDate,'ترحيل حركة دفترية',branch_id());q('INSERT INTO ledger_entries(account_id,entry_date,source_type,source_id,description,debit,credit,currency_id,exchange_rate,created_by,branch_id) VALUES(?,?,?,?,?,?,?,?,?,?,?)',[$account_id,$entryDate,$src,$srcid,$desc,$debit,$credit,$cur,$rate,user()['id']??0,branch_id()]);}
function ledger_branch($branchId,$account_id,$src,$srcid,$desc,$debit=0,$credit=0,$cur=1,$rate=1,$entryDate=null){$branchId=(int)$branchId;$entryDate=$entryDate?:date('Y-m-d');assert_accounting_open_v53($entryDate,'ترحيل حركة دفترية',$branchId);q('INSERT INTO ledger_entries(account_id,entry_date,source_type,source_id,description,debit,credit,currency_id,exchange_rate,created_by,branch_id) VALUES(?,?,?,?,?,?,?,?,?,?,?)',[$account_id,$entryDate,$src,$srcid,$desc,$debit,$credit,$cur,$rate,user()['id']??0,$branchId]);}
function balance_by_currency($account_id,$branchId=null){$branchId=(int)($branchId?:branch_id());$out=[];foreach(q('SELECT currency_id,COALESCE(SUM(debit-credit),0) balance FROM ledger_entries WHERE account_id=? AND branch_id=? GROUP BY currency_id',[$account_id,$branchId])->fetchAll() as $r){$out[(int)$r['currency_id']]=(float)$r['balance'];}return $out;}
function balance($account_id,$currencyId=null){if($currencyId!==null)return (float)q('SELECT COALESCE(SUM(debit-credit),0) FROM ledger_entries WHERE account_id=? AND branch_id=? AND currency_id=?',[$account_id,branch_id(),(int)$currencyId])->fetchColumn();$total=0;foreach(balance_by_currency($account_id) as $cid=>$bal)$total+=fx_convert($bal,$cid,1);return $total;}
function has_open_balance($account_id,$branchId=null){foreach(balance_by_currency($account_id,$branchId) as $bal){if(abs($bal)>0.001)return true;}return false;}
