function branch_record_allowed_v48($table,$id,$label='السجل'){
    $id=(int)$id; if(!$id)return false;
    try{$safe=preg_replace('/[^A-Za-z0-9_]/','',(string)$table);$row=q("SELECT branch_id FROM `$safe` WHERE id=?",[$id])->fetch(); if(!$row)return false; $bid=(int)($row['branch_id']??0); return $bid===0 || $bid===(int)branch_id();}catch(Throwable $e){return false;}
}
