function ensure_named_account($name,$type='عام',$nature='debit',$parentName=null){
    $id=q('SELECT id FROM accounts WHERE name=? LIMIT 1',[$name])->fetchColumn();
    if($id)return (int)$id;
    $parent=null;$prefix='9';
    if($parentName){$parent=q('SELECT id FROM accounts WHERE name=? LIMIT 1',[$parentName])->fetchColumn()?:null; if($parent)$prefix=q('SELECT account_no FROM accounts WHERE id=?',[$parent])->fetchColumn()?:'9';}
    $cnt=(int)q('SELECT COUNT(*) FROM accounts WHERE parent_id '.($parent?'=?':'IS NULL'),$parent?[$parent]:[])->fetchColumn();
    do{$no=$prefix.str_pad((string)(++$cnt),3,'0',STR_PAD_LEFT);$dup=q('SELECT id FROM accounts WHERE account_no=? LIMIT 1',[$no])->fetchColumn();}while($dup);
    q('INSERT INTO accounts(account_no,name,type,nature,currency_id,parent_id,created_at) VALUES(?,?,?,?,?,?,NOW())',[$no,$name,$type,$nature,1,$parent]);
    return (int)db()->lastInsertId();
}

function balance_legacy_ledger_groups($limit=500){
    try{
        $acc=ensure_named_account('فروقات تسوية قيود سابقة','حقوق ملكية','credit','حقوق الملكية');
        $groups=q("SELECT branch_id,source_type,COALESCE(source_id,0) sid,currency_id,ROUND(SUM(debit-credit),2) diff,COUNT(*) cnt FROM ledger_entries WHERE source_type<>'legacy_balance_fix' GROUP BY branch_id,source_type,COALESCE(source_id,0),currency_id HAVING ABS(diff)>0.009 LIMIT ".(int)$limit)->fetchAll();
        foreach($groups as $g){
            $diff=(float)$g['diff'];$cur=(int)$g['currency_id'];$src=(string)$g['source_type'];$sid=(int)$g['sid'];
            $exists=q('SELECT id FROM ledger_entries WHERE account_id=? AND source_type=? AND source_id=? AND currency_id=? AND description LIKE ? LIMIT 1',[$acc,$src,$sid,$cur,'تسوية تلقائية لقيد سابق%'])->fetchColumn();
            if($exists)continue;
            $bid=(int)($g['branch_id']??branch_id());
            if($diff>0) ledger_branch($bid,$acc,$src,$sid,'تسوية تلقائية لقيد سابق غير متوازن قبل تحديث ميزان المراجعة - '.$src.' #'.$sid,0,$diff,$cur,1);
            elseif($diff<0) ledger_branch($bid,$acc,$src,$sid,'تسوية تلقائية لقيد سابق غير متوازن قبل تحديث ميزان المراجعة - '.$src.' #'.$sid,abs($diff),0,$cur,1);
        }
    }catch(Throwable $e){}
}

