function ensure_entity_account_links(){
    try{
        $groups=['suppliers'=>['type'=>'مورد','group'=>'موردين المركز الرئيسي','nature'=>'credit'],'agents'=>['type'=>'وكيل','group'=>'وكلاء المركز الرئيسي','nature'=>'credit'],'offices'=>['type'=>'مكتب مخلص','group'=>'مكاتب مخلصة المركز الرئيسي','nature'=>'credit'],'banks'=>['type'=>'بنك','group'=>'بنوك المركز الرئيسي','nature'=>'debit'],'cashboxes'=>['type'=>'صندوق','group'=>'صناديق المركز الرئيسي','nature'=>'debit'],'employees'=>['type'=>'موظف','group'=>'موظفين المركز الرئيسي','nature'=>'debit'],'customers'=>['type'=>'عميل','group'=>'عملاء المركز الرئيسي','nature'=>'debit']];
        foreach($groups as $table=>$cfg){
            foreach(q("SELECT id,name,account_id,COALESCE(branch_id,1) branch_id FROM `$table` WHERE account_id IS NULL OR account_id=0")->fetchAll() as $r){
                $bid=(int)($r['branch_id']?:1);
                $aid=add_account_for_branch_v49($bid,$cfg['type'],$r['name'],$cfg['nature'],1);
                q("UPDATE `$table` SET account_id=? WHERE id=?",[$aid,$r['id']]);
            }
            $gid=q('SELECT id FROM accounts WHERE name=? LIMIT 1',[$cfg['group']])->fetchColumn();
            if($gid) q('UPDATE accounts SET parent_id=?, nature=? WHERE type=? AND name<>? AND (parent_id IS NULL OR parent_id=0 OR parent_id IN (1,2,3,4))',[$gid,$cfg['nature'],$cfg['type'],$cfg['group']]);
        }
        $gid=q('SELECT id FROM accounts WHERE name=? LIMIT 1',['موردين المركز الرئيسي'])->fetchColumn();
        if($gid) q("UPDATE accounts SET parent_id=?, type='مورد', nature='credit' WHERE name='المورد الرئيسي'",[$gid]);
    }catch(Throwable $e){}
}
