    $html='<div class="field"><label>'.e($label).'</label><div class="multi-filter-v16 report-dd-v34" data-report-dd><button type="button" class="multi-label" onclick="toggleMultiDrop(this)">'.e($btn).'</button><div class="multi-drop"><input placeholder="بحث" oninput="filterMultiOptions(this)"><label><input type="checkbox" data-all '.($cnt>=$total?'checked':'').' onchange="reportMultiSubmit(this)"> اختيار الكل</label>';
    foreach($rows as $r){$id=(string)$r['id'];$txt=$r['name']??$r['label']??$id;$checked=in_array($id,array_map('strval',$selected),true)?'checked':'';$html.='<label data-text="'.e($txt).'"><input type="checkbox" name="'.e($name).'[]" value="'.e($id).'" '.$checked.' onchange="reportMultiSubmit(this)"> '.e($txt).'</label>';}
    return $html.'</div></div></div>';
}
