function currency_rate_to_yer($currency_id,$manual_rate=null){
    $currency_id=(int)$currency_id;
    if($manual_rate!==null && (float)$manual_rate>0) return (float)$manual_rate;
    if($currency_id===1) return 1.0;       // YE
    if($currency_id===2) return 150.0;     // SR -> YE
    if($currency_id===3) return 525.0;     // USD -> YE
    return 1.0;
}
function default_fx_rate_between($from,$to){
    $from=(int)$from; $to=(int)$to;
    if($from===$to) return 1.0;
    $rates=[1=>1.0,2=>150.0,3=>525.0];
    return ($rates[$to]??1)>0 ? (($rates[$from]??1)/($rates[$to]??1)) : 1.0;
}
