function ensure_column_exists($table,$col,$definition){
    try{
        $table=preg_replace('/[^A-Za-z0-9_]/','',(string)$table);
        $col=preg_replace('/[^A-Za-z0-9_]/','',(string)$col);
        if($table===''||$col==='')return false;
        $exists=q("SHOW COLUMNS FROM `$table` LIKE '$col'")->fetch();
        if(!$exists){ q("ALTER TABLE `$table` ADD COLUMN `$col` $definition"); }
        return (bool)q("SHOW COLUMNS FROM `$table` LIKE '$col'")->fetch();
    }catch(Throwable $e){
        try{activity_log('schema.error','فشل ترحيل عمود','النظام',$table,$col,$col,$e->getMessage(),'فشل','خطر');}catch(Throwable $x){}
        return false;
    }
}
function accounting_schema_v53(){
    static $done=false; if($done)return; $done=true;
    try{q("CREATE TABLE IF NOT EXISTS financial_periods(id INT AUTO_INCREMENT PRIMARY KEY,branch_id INT NOT NULL,fiscal_year INT NOT NULL,start_date DATE NOT NULL,end_date DATE NOT NULL,status VARCHAR(20) DEFAULT 'open',closed_by INT NULL,closed_at DATETIME NULL,reopened_by INT NULL,reopened_at DATETIME NULL,closing_note TEXT NULL,created_by INT NULL,created_at DATETIME,UNIQUE KEY uniq_fin_period_branch_year(branch_id,fiscal_year),INDEX idx_fin_period_branch_dates(branch_id,start_date,end_date,status))");}catch(Throwable $e){}
    try{q("CREATE TABLE IF NOT EXISTS accounting_backups(id INT AUTO_INCREMENT PRIMARY KEY,branch_id INT NULL,file_name VARCHAR(220),file_path VARCHAR(500),file_size BIGINT DEFAULT 0,backup_type VARCHAR(30) DEFAULT 'full_sql',created_by INT NULL,created_at DATETIME,notes TEXT,INDEX(branch_id),INDEX(created_at))");}catch(Throwable $e){}
    try{ensure_column_exists('accounting_backups','branch_id','INT NULL');ensure_column_exists('accounting_backups','backup_type',"VARCHAR(30) DEFAULT 'full_sql'");}catch(Throwable $e){}
    try{
        $year=(int)date('Y');$start=$year.'-01-01';$end=$year.'-12-31';
        foreach(q('SELECT id FROM branches')->fetchAll() as $b){
            q('INSERT IGNORE INTO financial_periods(branch_id,fiscal_year,start_date,end_date,status,created_by,created_at) VALUES(?,?,?,?,?,?,NOW())',[(int)$b['id'],$year,$start,$end,'open',user()['id']??0]);
        }
    }catch(Throwable $e){}
}
function period_status_label_v53($s){return $s==='closed'?'مقفلة':'مفتوحة';}
function can_manage_financial_periods_v53(){return (int)(user()['role_id']??0)===1 || can_edit('accounting.periods');}
function can_create_backup_v53(){return (int)(user()['role_id']??0)===1 || can_edit('accounting.backup');}
function ensure_financial_period_v53($branchId,$year){
    accounting_schema_v53();$branchId=(int)($branchId?:branch_id());$year=(int)$year;if($year<2000||$year>2100)$year=(int)date('Y');
    $start=$year.'-01-01';$end=$year.'-12-31';
    q('INSERT IGNORE INTO financial_periods(branch_id,fiscal_year,start_date,end_date,status,created_by,created_at) VALUES(?,?,?,?,?,?,NOW())',[$branchId,$year,$start,$end,'open',user()['id']??0]);
    return q('SELECT * FROM financial_periods WHERE branch_id=? AND fiscal_year=? LIMIT 1',[$branchId,$year])->fetch();
}
function financial_period_for_date_v53($date,$branchId=null){
    accounting_schema_v53();$branchId=(int)($branchId?:branch_id());$date=substr((string)$date,0,10);if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$date))$date=date('Y-m-d');
    $p=q('SELECT * FROM financial_periods WHERE branch_id=? AND start_date<=? AND end_date>=? ORDER BY start_date DESC LIMIT 1',[$branchId,$date,$date])->fetch();
    return $p?:ensure_financial_period_v53($branchId,(int)substr($date,0,4));
}
function is_accounting_locked_v53($date,$branchId=null,&$period=null){
    $period=financial_period_for_date_v53($date,$branchId);
    return ($period['status']??'open')==='closed';
}
function assert_accounting_open_v53($date,$action='تنفيذ العملية',$branchId=null){
    $p=null;if(is_accounting_locked_v53($date,$branchId,$p)){
        throw new RuntimeException($action.' مرفوض: الفترة المالية '.$p['fiscal_year'].' مقفلة من '.$p['start_date'].' إلى '.$p['end_date'].'. أعد فتح الفترة أولاً من الإقفال المالي.');
    }
}
function period_balance_diffs_v53($from,$to,$branchId=null){
    $branchId=(int)($branchId?:branch_id());$rows=q("SELECT l.currency_id,COALESCE(SUM(l.debit),0) debit,COALESCE(SUM(l.credit),0) credit FROM ledger_entries l LEFT JOIN vouchers v ON l.source_type='voucher' AND v.id=l.source_id LEFT JOIN journal_entries je ON l.source_type='journal' AND je.id=l.source_id WHERE l.branch_id=? AND DATE(COALESCE(v.voucher_date,je.entry_date,l.entry_date)) BETWEEN ? AND ? GROUP BY l.currency_id",[$branchId,$from,$to])->fetchAll();
    $out=[];foreach($rows as $r){$diff=round((float)$r['debit']-(float)$r['credit'],2);$out[]=['currency_id'=>(int)$r['currency_id'],'code'=>currency_code($r['currency_id']),'debit'=>(float)$r['debit'],'credit'=>(float)$r['credit'],'diff'=>$diff];}
    return $out;
}
function backup_dir_v53(){
    $dir=__DIR__.DIRECTORY_SEPARATOR.'storage'.DIRECTORY_SEPARATOR.'backups';
    if(!is_dir($dir))@mkdir($dir,0775,true);
    return $dir;
}
function sql_literal_v53($v){return $v===null?'NULL':db()->quote((string)$v);}
function create_database_backup_v53($note=''){
    accounting_schema_v53();$dir=backup_dir_v53();if(!is_dir($dir)||!is_writable($dir))throw new RuntimeException('مجلد النسخ الاحتياطي غير قابل للكتابة: '.$dir);
    $file='ababilsoft_full_'.date('Ymd_His').'.sql';$path=$dir.DIRECTORY_SEPARATOR.$file;$fh=fopen($path,'wb');if(!$fh)throw new RuntimeException('تعذر إنشاء ملف النسخة الاحتياطية');
    fwrite($fh,"-- AbabilSoft SQL backup\n-- Created at ".date('Y-m-d H:i:s')."\nSET NAMES utf8mb4;\nSET FOREIGN_KEY_CHECKS=0;\n\n");$tables=[];foreach(q('SHOW TABLES')->fetchAll(PDO::FETCH_NUM) as $r)$tables[]=$r[0];$rowCount=0;
    foreach($tables as $t){$safe=str_replace('`','``',$t);$cr=q("SHOW CREATE TABLE `$safe`")->fetch();$create=$cr['Create Table']??array_values($cr)[1]??'';fwrite($fh,"\nDROP TABLE IF EXISTS `$safe`;\n".$create.";\n\n");$stmt=q("SELECT * FROM `$safe`");while($row=$stmt->fetch(PDO::FETCH_ASSOC)){$cols=array_map(fn($c)=>'`'.str_replace('`','``',$c).'`',array_keys($row));$vals=array_map('sql_literal_v53',array_values($row));fwrite($fh,'INSERT INTO `'.$safe.'` ('.implode(',',$cols).') VALUES ('.implode(',',$vals).");\n");$rowCount++;}fwrite($fh,"\n");}
    fwrite($fh,"SET FOREIGN_KEY_CHECKS=1;\n");fclose($fh);$size=(int)filesize($path);
    q('INSERT INTO accounting_backups(branch_id,file_name,file_path,file_size,backup_type,created_by,created_at,notes) VALUES(?,?,?,?,?,?,NOW(),?)',[branch_id(),$file,$path,$size,'full_sql',user()['id']??0,$note]);
    activity_log('backup.create','إنشاء نسخة احتياطية','الإدارة','backup',db()->lastInsertId(),$file,'عدد الصفوف: '.$rowCount.' | الحجم: '.$size,'ناجح','حساس');
    return ['file'=>$file,'path'=>$path,'size'=>$size,'rows'=>$rowCount];
}
function repair_ledger_entry_dates_v53(){
    static $done=false; if($done)return; $done=true;
    try{q("UPDATE ledger_entries l JOIN vouchers v ON l.source_type='voucher' AND v.id=l.source_id AND v.branch_id=l.branch_id SET l.entry_date=v.voucher_date WHERE v.voucher_date IS NOT NULL AND DATE(l.entry_date)<>v.voucher_date");}catch(Throwable $e){}
    try{q("UPDATE ledger_entries l JOIN journal_entries je ON l.source_type='journal' AND je.id=l.source_id AND je.branch_id=l.branch_id SET l.entry_date=je.entry_date WHERE je.entry_date IS NOT NULL AND DATE(l.entry_date)<>je.entry_date");}catch(Throwable $e){}
    try{q("UPDATE ledger_entries l JOIN transactions t ON l.source_type='transaction' AND t.id=l.source_id AND t.branch_id=l.branch_id SET l.entry_date=t.transaction_date WHERE t.transaction_date IS NOT NULL AND DATE(l.entry_date)<>t.transaction_date");}catch(Throwable $e){}
    try{q("UPDATE journal_entries je JOIN transactions t ON (t.supplier_journal_id=je.id OR t.agent_journal_id=je.id) AND t.branch_id=je.branch_id SET je.entry_date=t.transaction_date WHERE t.transaction_date IS NOT NULL AND DATE(je.entry_date)<>t.transaction_date");}catch(Throwable $e){}
    try{q("UPDATE ledger_entries l JOIN transactions t ON (t.supplier_journal_id=l.source_id OR t.agent_journal_id=l.source_id) AND l.source_type='journal' AND t.branch_id=l.branch_id SET l.entry_date=t.transaction_date WHERE t.transaction_date IS NOT NULL AND DATE(l.entry_date)<>t.transaction_date");}catch(Throwable $e){}
}
