function device_info_v45(){
    $ua=$_SERVER['HTTP_USER_AGENT']??'';
    $device=(preg_match('/Mobile|Android|iPhone|iPad/i',$ua)?'Mobile':'Desktop');
    if(preg_match('/iPad/i',$ua))$device='Tablet';
    $os='Unknown'; foreach(['Windows'=>'Windows','Android'=>'Android','iPhone'=>'iOS','iPad'=>'iPadOS','Mac OS'=>'macOS','Linux'=>'Linux'] as $needle=>$name){if(stripos($ua,$needle)!==false){$os=$name;break;}}
    $browser='Unknown'; foreach(['Edg'=>'Edge','Chrome'=>'Chrome','Firefox'=>'Firefox','Safari'=>'Safari','OPR'=>'Opera'] as $needle=>$name){if(stripos($ua,$needle)!==false){$browser=$name;break;}}
    $hash=hash('sha256',$ua.'|'.($_SERVER['REMOTE_ADDR']??''));
    return ['device'=>$device,'os'=>$os,'browser'=>$browser,'ip'=>$_SERVER['REMOTE_ADDR']??'','ua'=>substr($ua,0,900),'hash'=>$hash,'label'=>$device.' / '.$os.' / '.$browser];
}
function device_info_from_ua_v45($ua){$device=(preg_match('/Mobile|Android|iPhone|iPad/i',(string)$ua)?'Mobile':'Desktop');$os='Unknown';foreach(['Windows'=>'Windows','Android'=>'Android','iPhone'=>'iOS','iPad'=>'iPadOS','Mac OS'=>'macOS','Linux'=>'Linux'] as $n=>$v){if(stripos((string)$ua,$n)!==false){$os=$v;break;}}$browser='Unknown';foreach(['Edg'=>'Edge','Chrome'=>'Chrome','Firefox'=>'Firefox','Safari'=>'Safari','OPR'=>'Opera'] as $n=>$v){if(stripos((string)$ua,$n)!==false){$browser=$v;break;}}return $device.' / '.$os.' / '.$browser;}
