function license_check_clock_v45(){
    $now=now();$last=setting('last_run_at','');
    if($last && strtotime($now)+600 < strtotime($last)){set_setting('license_screen_locked','1');set_setting('license_locked_reason','تم اكتشاف تغيير غير طبيعي في تاريخ الجهاز. يرجى التواصل مع الشركة.');}
