}
function license_state_v45(){
    license_bootstrap_v45(); $end=setting('license_end',''); $locked=setting_bool('license_screen_locked',false); $status=setting('license_status','trial');
    $expired=$end && strtotime($end)<time(); if($expired)$status='expired';
    $days=$end?ceil((strtotime($end)-time())/86400):0;
    return ['status'=>$status,'type'=>setting('license_type','trial'),'start'=>setting('license_start',''),'end'=>$end,'expired'=>$expired,'locked'=>$locked,'days'=>$days,'attempts'=>(int)setting('license_attempts','0'),'reason'=>setting('license_locked_reason','')];
}
function license_is_active_v45(){ $s=license_state_v45(); return !$s['locked'] && !$s['expired']; }
