function license_guard_route_v45($r){
    if(!logged())return; $s=license_state_v45();
    $allowed=['dashboard','company_settings','print_settings','tenants','tenant_save','tenant_switch','license_unlock','license_activate','logout','notifications','notification_read','notification_ack'];
    $isWrite=$_SERVER['REQUEST_METHOD']==='POST'||preg_match('/(_save|_update|_delete|_reverse|_due|_switch|_mark_read)$/',$r);
    if(($s['locked']||$s['expired']) && !in_array($r,$allowed,true)){
        if($isWrite){flash('الترخيص منتهي أو مقفل. النظام في وضع القراءة فقط، يرجى التواصل مع الشركة.','err');go('company_settings',['tab'=>'license']);}
