    if($aid){$where[]='l.account_id=?';$par[]=$aid;} $where[]='l.branch_id=?';$par[]=branch_id(); if($from){$where[]='DATE(COALESCE(v.voucher_date,je.entry_date,l.entry_date))>=?';$par[]=$from;}if($to){$where[]='DATE(COALESCE(v.voucher_date,je.entry_date,l.entry_date))<=?';$par[]=$to;}if($cur!=='all'){$where[]='l.currency_id=?';$par[]=(int)$cur;}if($stype!=='all'){$where[]='l.source_type=?';$par[]=$stype;}
