    $sql="SELECT l.*,a.name account_name,a.account_no,c.code cur_code,c.name cur_name,v.voucher_no,je.entry_no,COALESCE(v.voucher_no,je.entry_no,CAST(l.source_id AS CHAR)) AS doc_no, COALESCE(CONCAT(v.voucher_date,' ',v.voucher_time),CONCAT(je.entry_date,' ',je.entry_time),l.entry_date) AS doc_datetime FROM ledger_entries l LEFT JOIN accounts a ON a.id=l.account_id LEFT JOIN currencies c ON c.id=l.currency_id LEFT JOIN vouchers v ON l.source_type='voucher' AND v.id=l.source_id LEFT JOIN journal_entries je ON l.source_type='journal' AND je.id=l.source_id ".($where?' WHERE '.implode(' AND ',$where):'');
