WHERE id=? AND branch_id=?',[$jid,$oid,branch_id()]);q('UPDATE transactions SET is_relayed=1,office_id=? WHERE id=? AND branch_id=?',[$o['id'],$id,branch_id()]);$done++;}if($done<1)throw new RuntimeException('لا توجد معاملات صالحة للترحيل أو كلها مرحلة سابقاً');tx_commit_v52($started);flash('تم الترحيل بقيود متوازنة');go('transfer');}catch(Throwable $e){tx_rollback_v52($started);flash('لا يمكن الترحيل: '.$e->getMessage(),'err');go('transfer');}
