s $r){q('UPDATE office_transfers SET is_reversed=1,reverse_journal_id=?,reverse_discount=?,reverse_currency_id=?,reverse_note=? WHERE id=? AND branch_id=?',[$jid,($discountType==='total'&&$discountAmount>0)?round($discountAmount/$count,2):(($discountType==='per_person')?$discountAmount:0),$discountCur,$baseDesc,$r['id'],branch_id()]);q('UPDATE transactions SET is_relayed=0,office_id=NULL WHERE id=? AND branch_id=?',[$r['transaction_id'],branch_id()]);}tx_commit_v52($started);flash('تم إلغاء الترحيل بقيد عكسي متوازن');go('journal_view',['id'=>$jid]);}catch(Throwable $e){tx_rollback_v52($started);flash('لا يمكن إلغاء الترحيل: '.$e->getMessage(),'err');go('transfer');}
}
