function page_login(){
    tenant_select_from_request_v56();
    $tenantRows=tenant_rows_v56(true);
    $selectedTenant=current_tenant_v56(true);
    if($_SERVER['REQUEST_METHOD']==='POST'){
        $username=$_POST['username']??''; $pass=$_POST['password']??''; $dev=device_info_v45();
        $row=q('SELECT u.*,r.role_key FROM users u LEFT JOIN roles r ON r.id=u.role_id WHERE u.username=? AND u.is_active=1',[$username])->fetch();
        if($row&&password_verify($pass,$row['password_hash'])){
            $isNew=0; try{$known=q('SELECT id FROM known_user_devices WHERE user_id=? AND device_hash=?',[$row['id'],$dev['hash']])->fetch(); if($known){q('UPDATE known_user_devices SET last_seen=NOW(),login_count=login_count+1,ip_address=? WHERE id=?',[$dev['ip'],$known['id']]);}else{$isNew=1;q('INSERT INTO known_user_devices(user_id,device_hash,device_type,os_name,browser_name,ip_address,first_seen,last_seen) VALUES(?,?,?,?,?,?,NOW(),NOW())',[$row['id'],$dev['hash'],$dev['device'],$dev['os'],$dev['browser'],$dev['ip']]);}}catch(Throwable $e){}
