function tx_action_payload_for_customer($customer_id){
    ensure_customer_page_schema_v54();
    $txs=q('SELECT t.*,c.account_id customer_account_id,s.name service,ss.name status,ag.name agent,o.name office,sup.name supplier FROM transactions t JOIN customers c ON c.id=t.customer_id JOIN services s ON s.id=t.service_id LEFT JOIN service_statuses ss ON ss.id=t.status_id LEFT JOIN agents ag ON ag.id=t.agent_id LEFT JOIN offices o ON o.id=t.office_id LEFT JOIN suppliers sup ON sup.id=t.supplier_id WHERE t.customer_id=? ORDER BY t.created_at DESC,t.id DESC',[$customer_id])->fetchAll();
    foreach($txs as &$t){
        $t['has_visa']=!empty($t['visa_profession_id'])||!empty($t['visa_number']);
        $t['is_relayed_label']=((int)($t['is_relayed']??0)===1)?'مرسلة':'غير مرسلة';
        $t['actions']=['office'=>((int)($t['is_relayed']??0)===1?'عرض المكتب المخلص':'إرسال إلى مكتب مخلص'),'status'=>'تغيير الحالة','refund'=>'مردود','visa'=>$t['has_visa']?'عرض التأشيرة':'إنزال تأشيرة','delivery'=>'تسليم','view'=>'عرض'];
    }
    return $txs;
}
function service_status_map_json(){
    $rows=q('SELECT s.id service_id,st.id status_id,st.name status_name,st.sort_order FROM services s LEFT JOIN service_statuses st ON st.service_id=s.id ORDER BY s.id,st.sort_order,st.id')->fetchAll();
    $map=[];foreach($rows as $r){$sid=(int)$r['service_id']; if(!isset($map[$sid]))$map[$sid]=[]; if($r['status_id'])$map[$sid][]=['id'=>(int)$r['status_id'],'name'=>$r['status_name']];}
    return json_encode($map,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES);
}
