}

function ensure_customer_page_schema_v54(){
    static $done=false; if($done)return; $done=true;
    try{branch_schema_v41();}catch(Throwable $e){}
    try{q("CREATE TABLE IF NOT EXISTS customers(id INT AUTO_INCREMENT PRIMARY KEY,account_id INT NULL,name VARCHAR(180),passport_no VARCHAR(100),phone VARCHAR(50),profession VARCHAR(150),doc_type VARCHAR(50),profession_id INT NULL,agent_id INT NULL,customer_source VARCHAR(50),notes TEXT,created_at DATETIME,branch_id INT NULL,created_by INT NULL)");}catch(Throwable $e){}
    try{q("CREATE TABLE IF NOT EXISTS visa_batches(id INT AUTO_INCREMENT PRIMARY KEY,supplier_id INT NULL,supplier_name VARCHAR(180),visa_number VARCHAR(100),registry_number VARCHAR(100),company_name VARCHAR(180),visa_type VARCHAR(50),price DECIMAL(18,2) DEFAULT 0,currency_id INT DEFAULT 2,total_quantity INT DEFAULT 0,notes TEXT,created_by INT NULL,created_at DATETIME,branch_id INT NULL)");}catch(Throwable $e){}
    try{q("CREATE TABLE IF NOT EXISTS visa_professions(id INT AUTO_INCREMENT PRIMARY KEY,batch_id INT NULL,profession_name VARCHAR(180),quantity INT DEFAULT 0,authorized_qty INT DEFAULT 0,used_qty INT DEFAULT 0,created_at DATETIME,branch_id INT NULL)");}catch(Throwable $e){}
    try{
        foreach(['account_id'=>'INT NULL','name'=>'VARCHAR(180) NULL','passport_no'=>'VARCHAR(100) NULL','phone'=>'VARCHAR(50) NULL','profession'=>'VARCHAR(150) NULL','doc_type'=>'VARCHAR(50) NULL','profession_id'=>'INT NULL','agent_id'=>'INT NULL','customer_source'=>'VARCHAR(50) NULL','notes'=>'TEXT NULL','created_at'=>'DATETIME NULL','branch_id'=>'INT NULL','created_by'=>'INT NULL'] as $c=>$d) ensure_column_exists('customers',$c,$d);
        foreach(['branch_id'=>'INT NULL','account_id'=>'INT NULL'] as $c=>$d){ensure_column_exists('agents',$c,$d);ensure_column_exists('suppliers',$c,$d);ensure_column_exists('offices',$c,$d);}
        q("UPDATE customers SET branch_id=1 WHERE branch_id IS NULL OR branch_id=0");
        q("UPDATE agents SET branch_id=1 WHERE branch_id IS NULL OR branch_id=0");
        q("UPDATE suppliers SET branch_id=1 WHERE branch_id IS NULL OR branch_id=0");
        q("UPDATE offices SET branch_id=1 WHERE branch_id IS NULL OR branch_id=0");
    }catch(Throwable $e){}
    try{
        foreach(['supplier_id'=>'INT NULL','supplier_name'=>'VARCHAR(180) NULL','visa_number'=>'VARCHAR(100) NULL','registry_number'=>'VARCHAR(100) NULL','company_name'=>'VARCHAR(180) NULL','visa_type'=>'VARCHAR(50) NULL','price'=>'DECIMAL(18,2) DEFAULT 0','currency_id'=>'INT DEFAULT 2','total_quantity'=>'INT DEFAULT 0','notes'=>'TEXT NULL','created_by'=>'INT NULL','created_at'=>'DATETIME NULL','branch_id'=>'INT NULL'] as $c=>$d) ensure_column_exists('visa_batches',$c,$d);
        foreach(['batch_id'=>'INT NULL','profession_name'=>'VARCHAR(180) NULL','quantity'=>'INT DEFAULT 0','authorized_qty'=>'INT DEFAULT 0','used_qty'=>'INT DEFAULT 0','created_at'=>'DATETIME NULL','branch_id'=>'INT NULL'] as $c=>$d) ensure_column_exists('visa_professions',$c,$d);
        q("UPDATE visa_batches SET branch_id=1 WHERE branch_id IS NULL OR branch_id=0");
        q("UPDATE visa_professions p JOIN visa_batches b ON b.id=p.batch_id SET p.branch_id=b.branch_id WHERE p.branch_id IS NULL OR p.branch_id=0");
    }catch(Throwable $e){}
    try{
        foreach(['customer_id'=>'INT NULL','service_id'=>'INT NULL','status_id'=>'INT NULL','visa_batch_id'=>'INT NULL','visa_profession_id'=>'INT NULL','visa_number'=>'VARCHAR(100) NULL','registry_number'=>'VARCHAR(100) NULL','company_name'=>'VARCHAR(180) NULL','visa_type'=>'VARCHAR(50) NULL','supplier_id'=>'INT NULL','office_id'=>'INT NULL','agent_id'=>'INT NULL','sale_type'=>'VARCHAR(50) NULL','agent_commission'=>'DECIMAL(18,2) DEFAULT 0','price'=>'DECIMAL(18,2) DEFAULT 0','currency_id'=>'INT DEFAULT 2','transaction_date'=>'DATE NULL','notes'=>'TEXT NULL','is_relayed'=>'TINYINT DEFAULT 0','is_delivered'=>'TINYINT DEFAULT 0','created_by'=>'INT NULL','created_at'=>'DATETIME NULL','branch_id'=>'INT NULL','supplier_journal_id'=>'INT NULL','agent_journal_id'=>'INT NULL'] as $c=>$d) ensure_column_exists('transactions',$c,$d);
        q("UPDATE transactions SET branch_id=1 WHERE branch_id IS NULL OR branch_id=0");
    }catch(Throwable $e){}
}

function ensure_notifications_page_schema_v54(){
    static $done=false; if($done)return; $done=true;
    try{q("CREATE TABLE IF NOT EXISTS notifications(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,notification_type VARCHAR(50),title VARCHAR(220),body TEXT,severity VARCHAR(50),is_read TINYINT DEFAULT 0,show_at DATETIME NULL,repeat_rule VARCHAR(80),created_by INT NULL,created_at DATETIME,read_at DATETIME NULL)");}catch(Throwable $e){}
    try{q("CREATE TABLE IF NOT EXISTS notification_settings(id INT PRIMARY KEY DEFAULT 1,position VARCHAR(50) DEFAULT 'top-right',duration_seconds INT DEFAULT 5,show_countdown TINYINT DEFAULT 1,show_close TINYINT DEFAULT 1,play_sound TINYINT DEFAULT 0,max_visible INT DEFAULT 3,color_scheme VARCHAR(50) DEFAULT 'info')");}catch(Throwable $e){}
    try{
        foreach(['user_id'=>'INT NULL','notification_type'=>"VARCHAR(50) DEFAULT 'system'",'title'=>'VARCHAR(220) NULL','body'=>'TEXT NULL','severity'=>"VARCHAR(50) DEFAULT 'info'",'is_read'=>'TINYINT DEFAULT 0','show_at'=>'DATETIME NULL','repeat_rule'=>'VARCHAR(80) NULL','created_by'=>'INT NULL','created_at'=>'DATETIME NULL','read_at'=>'DATETIME NULL','delivery_status'=>'VARCHAR(50) DEFAULT NULL','response_status'=>"VARCHAR(50) DEFAULT ''",'delivered_at'=>'DATETIME NULL','responded_at'=>'DATETIME NULL','requires_ack'=>'TINYINT DEFAULT 0','target_branch_id'=>'INT NULL','device_label'=>'VARCHAR(220) NULL','position'=>'VARCHAR(50) NULL','color_scheme'=>'VARCHAR(50) NULL'] as $c=>$d) ensure_column_exists('notifications',$c,$d);
        $hasN=q("SHOW COLUMNS FROM notifications LIKE 'ntype'")->fetch();
        if($hasN) q("UPDATE notifications SET notification_type=COALESCE(NULLIF(notification_type,''),ntype,'system') WHERE notification_type IS NULL OR notification_type=''");
        q("UPDATE notifications SET notification_type='system' WHERE notification_type IS NULL OR notification_type=''");
        q("UPDATE notifications SET severity='info' WHERE severity IS NULL OR severity=''");
        q("UPDATE notifications SET created_at=COALESCE(created_at,NOW()) WHERE created_at IS NULL");
        q("UPDATE notifications SET delivery_status=COALESCE(NULLIF(delivery_status,''),'لم يصله') WHERE delivery_status IS NULL OR delivery_status=''");
    }catch(Throwable $e){}
    try{
        foreach(['position'=>"VARCHAR(50) DEFAULT 'top-right'",'duration_seconds'=>'INT DEFAULT 5','show_countdown'=>'TINYINT DEFAULT 1','show_close'=>'TINYINT DEFAULT 1','play_sound'=>'TINYINT DEFAULT 0','max_visible'=>'INT DEFAULT 3','success_color'=>"VARCHAR(30) DEFAULT '#16a34a'",'warning_color'=>"VARCHAR(30) DEFAULT '#f59e0b'",'error_color'=>"VARCHAR(30) DEFAULT '#dc2626'",'info_color'=>"VARCHAR(30) DEFAULT '#0ea5e9'",'color_scheme'=>"VARCHAR(50) DEFAULT 'info'",'custom_bg'=>"VARCHAR(30) DEFAULT ''",'custom_text'=>"VARCHAR(30) DEFAULT ''",'require_ack_default'=>'TINYINT DEFAULT 0','system_center_enabled'=>'TINYINT DEFAULT 1','browser_leave_only'=>'TINYINT DEFAULT 1'] as $c=>$d) ensure_column_exists('notification_settings',$c,$d);
        q("INSERT IGNORE INTO notification_settings(id) VALUES(1)");
    }catch(Throwable $e){}
    try{ensure_index_v50('notifications','idx_notifications_user_state',['user_id','delivery_status','is_read']);}catch(Throwable $e){}
}

