function act_master_save(){$type=$_POST['type'];$table=['suppliers'=>'suppliers','agents'=>'agents','offices'=>'offices','banks'=>'banks','cashboxes'=>'cashboxes'][$type]??'suppliers';$accType=['suppliers'=>'مورد','agents'=>'وكيل','offices'=>'مكتب مخلص','banks'=>'بنك','cashboxes'=>'صندوق'][$type];$name=trim($_POST['name']??'');if($name===''){flash('الاسم مطلوب','err');go('master',['type'=>$type]);}$phone=trim($_POST['phone']??'');$col=$table==='banks'?'bank_account_no':'phone';$ex=q("SELECT id FROM `$table` WHERE branch_id=? AND (name=?".($phone!==''?" OR `$col`=?":"").") LIMIT 1",$phone!==''?[branch_id(),$name,$phone]:[branch_id(),$name])->fetchColumn();if($ex){v13_notice('لا يمكن الإضافة','هذا السجل موجود سابقاً، لا يمكن تكراره.','master',route('master_view',['type'=>$type,'id'=>$ex]));return;}$nature=in_array($accType,['مورد','مكتب مخلص'])?'credit':'debit';$aid=add_account($accType,$name,$nature,1); if($table==='banks') q('INSERT INTO banks(account_id,name,bank_account_no,notes,created_at,branch_id) VALUES(?,?,?,?,NOW(),?)',[$aid,$name,$_POST['phone'],$_POST['notes'],branch_id()]); elseif($table==='cashboxes') q('INSERT INTO cashboxes(account_id,name,notes,created_at,branch_id) VALUES(?,?,?,NOW(),?)',[$aid,$name,$_POST['notes'],branch_id()]); else q("INSERT INTO `$table`(account_id,name,phone,notes,created_at,branch_id) VALUES(?,?,?,?,NOW(),?)",[$aid,$name,$_POST['phone'],$_POST['notes'],branch_id()]); q('UPDATE accounts SET branch_id=? WHERE id=?',[branch_id(),$aid]); flash('تم الحفظ');go('master',['type'=>$type]);}

function master_meta_v44($type){
    $map=['suppliers'=>['المورد','الموردين','suppliers','مورد','phone'], 'agents'=>['الوكيل','الوكلاء','agents','وكيل','phone'], 'offices'=>['المكتب المخلص','المكاتب المخلصة','offices','مكتب مخلص','phone'], 'banks'=>['البنك','البنوك','banks','بنك','bank_account_no'], 'cashboxes'=>['الصندوق','الصناديق','cashboxes','صندوق','notes']];
    return $map[$type]??$map['suppliers'];
}
function page_master_view(){
    $type=$_GET['type']??'suppliers';$id=(int)($_GET['id']??0);[$single,$plural,$table,$accType,$phoneCol]=master_meta_v44($type);
    $row=q("SELECT * FROM `$table` WHERE id=? AND branch_id=?",[$id,branch_id()])->fetch();
