function act_master_update(){
    verify();$type=$_POST['type']??'suppliers';$id=(int)($_POST['id']??0);[$single,$plural,$table,$accType,$phoneCol]=master_meta_v44($type);
    if(!can_edit('master.edit')){system_no_permission('master');return;}
    $row=q("SELECT * FROM `$table` WHERE id=? AND branch_id=?",[$id,branch_id()])->fetch();if(!$row){v13_notice('لا يمكن التعديل','السجل غير موجود في هذا الفرع.','master');return;}
    $name=trim($_POST['name']??'');if($name===''){flash('الاسم مطلوب','err');go('master_view',['type'=>$type,'id'=>$id,'edit'=>1]);}
    $phone=trim($_POST['phone']??'');$notes=$_POST['notes']??'';
    if($table==='banks')q('UPDATE banks SET name=?,bank_account_no=?,notes=? WHERE id=? AND branch_id=?',[$name,$phone,$notes,$id,branch_id()]);
    elseif($table==='cashboxes')q('UPDATE cashboxes SET name=?,notes=? WHERE id=? AND branch_id=?',[$name,$notes,$id,branch_id()]);
    else q("UPDATE `$table` SET name=?,phone=?,notes=? WHERE id=? AND branch_id=?",[$name,$phone,$notes,$id,branch_id()]);
    if(!empty($row['account_id']))q('UPDATE accounts SET name=? WHERE id=?',[$name,$row['account_id']]);
    activity_log('master.update','تعديل '.$single,'الأدلة',$table,$id,$name,'تعديل بيانات '.$single);
    flash('تم تعديل البيانات');go('master_view',['type'=>$type,'id'=>$id]);
}

