$e['account_id']])?>">كشف</a><a class="btn btn-sm btn-outline" href="<?=route('voucher_form',['type'=>'قبض','account_id'=>$e['account_id']])?>">قبض</a><a class="btn btn-sm btn-outline" href="<?=route('voucher_form',['type'=>'صرف','account_id'=>$e['account_id']])?>">صرف</a><?php endif;?></td><td><a class="btn btn-sm btn-outline" href="<?=route('employee_view',['id'=>$e['id']])?>">عرض</a><?php if(can_edit('employees.edit')):?><a class="btn btn-sm btn-outline" href="<?=route('employee_view',['id'=>$e['id'],'edit'=>1])?>">تعديل</a><?php endif;?><?php $eu=user_id_for_employee_v39($e['id']);?><a class="btn btn-sm btn-navy" href="<?=route('users',['employee_id'=>$e['id']])?>"><?= $eu?'إدارة الصلاحيات':'إنشاء مستخدم' ?></a></td></tr><?php endforeach;?></table></div></div><?php render('الموظفين',ob_get_clean(),'data');}
function act_employee_save(){$name=trim($_POST['name']??'');$phone=trim($_POST['phone']??'');if($name===''){flash('اسم الموظف مطلوب','err');go('employees');}$ex=q('SELECT id FROM employees WHERE branch_id=? AND (name=?'.($phone!==''?' OR phone=?':'').') LIMIT 1',$phone!==''?[branch_id(),$name,$phone]:[branch_id(),$name])->fetchColumn();if($ex){v13_notice('لا يمكن الإضافة','هذا الموظف موجود سابقاً.','employees',route('employee_view',['id'=>$ex]));return;}$aid=add_account('موظف',$name,'debit',1);q('INSERT INTO employees(account_id,name,phone,job_title,salary,created_at,branch_id) VALUES(?,?,?,?,?,NOW(),?)',[$aid,$name,$_POST['phone'],$_POST['job_title'],$_POST['salary']?:0,branch_id()]);q('UPDATE accounts SET branch_id=? WHERE id=?',[branch_id(),$aid]);flash('تم حفظ الموظف');go('employees');}
function act_employee_due(){
    $e=q('SELECT * FROM employees WHERE id=? AND branch_id=?',[$_POST['employee_id'],branch_id()])->fetch();
    if(!$e){v13_notice('لا يمكن التسجيل','الموظف غير موجود.','employees');return;}
    if(!ensure_same_branch_v42($e['branch_id']??branch_id(),'الموظف'))return;
    $branchId=(int)($e['branch_id']??branch_id());
    $type=trim($_POST['entitlement_type']??'استحقاق');
    $date=$_POST['entitlement_date']?:date('Y-m-d');
    $amount=(float)($_POST['amount']??0);
    $cur=(int)($_POST['currency_id']?:1);
    if($amount<=0){flash('مبلغ الاستحقاق يجب أن يكون أكبر من صفر','err');go('employees');}
    try{assert_accounting_open_v53($date,'تسجيل استحقاق موظف',$branchId);}catch(Throwable $e){flash($e->getMessage(),'err');go('employees');}
    if(empty($e['account_id'])){
        $aid=add_account_for_branch_v49($branchId,'موظف',$e['name'],'debit',$cur);
        q('UPDATE employees SET account_id=? WHERE id=? AND branch_id=?',[$aid,$e['id'],$branchId]);
        $e['account_id']=$aid;
    }
    $desc='استحقاق '.$type.' للموظف '.$e['name'].' بتاريخ '.$date.' بمبلغ '.money($amount).' '.currency_code($cur).' - بيان تلقائي من النظام';
    q('INSERT INTO employee_entitlements(employee_id,entitlement_type,amount,currency_id,entitlement_date,description,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,?,NOW(),?)',[$e['id'],$type,$amount,$cur,$date,$desc,user()['id'],$branchId]);
    $expenseAcc=branch_expense_account_v49('استحقاقات الموظفين',$branchId);
    create_journal_with_lines(next_unique_code_v52('JV','journal_entries','entry_no',$branchId),'استحقاق موظف',$desc,$cur,[
        ['account_id'=>$expenseAcc,'debit'=>$amount,'credit'=>0,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc],
        ['account_id'=>$e['account_id'],'debit'=>0,'credit'=>$amount,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc]
    ],$branchId,$date);
    flash('تم تسجيل الاستحقاق بقيد مزدوج متوازن في كشف الموظف');
    go('employees');
}
function page_visa_stock(){ob_start();?><div class="page-title"><h2>مخزون التأشيرات</h2><p>المهن مربوطة بدليل المهن، والمتاح مربوط بتنزيل التأشيرة للعميل، وغير المفوض مربوط بالتفويض.</p></div><div class="card"><form method="post" action="<?=route('visa_save')?>"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><div class="field"><label>المورد</label><select name="supplier_id"><option value="">بدون</option><?=opts('suppliers')?></select></div><div class="field"><label>رقم التأشيرة</label><input name="visa_number" required></div><div class="field"><label>رقم السجل</label><input name="registry_number"></div><div class="field"><label>الشركة/المؤسسة</label><input name="company_name"></div><div class="field"><label>نوع التأشيرة</label><select name="visa_type"><option>عادية</option><option>فردية</option></select></div><div class="field price-inline"><label>السعر</label><div class="price-currency-line"><input type="number" step="0.01" name="price"><span><?=currency_mini('currency_id',2)?></span></div><small class="muted">اختر العملة من نفس سطر السعر.</small></div><div class="field"><label>العدد الإجمالي</label><input type="number" name="total_quantity" required></div></div><h3>المهن</h3><table class="table"><tbody id="profbody"><tr><td><select name="prof_name[]" required><option value="">اختر المهنة من الدليل</option><?php foreach(q('SELECT * FROM professions WHERE is_active=1 ORDER BY name')->fetchAll() as $pr):?><option value="<?=e($pr['name'])?>"><?=e($pr['profession_no'].' - '.$pr['name'])?></option><?php endforeach;?></select></td><td><input name="prof_qty[]" type="number" placeholder="العدد" required></td><td><button type="button" class="btn btn-sm btn-outline" data-del-row>حذف</button></td></tr></tbody></table><template id="proftpl"><tr><td><select name="prof_name[]" required><option value="">اختر المهنة من الدليل</option><?php foreach(q('SELECT * FROM professions WHERE is_active=1 ORDER BY name')->fetchAll() as $pr):?><option value="<?=e($pr['name'])?>"><?=e($pr['profession_no'].' - '.$pr['name'])?></option><?php endforeach;?></select></td><td><input name="prof_qty[]" type="number" placeholder="العدد" required></td><td><button type="button" class="btn btn-sm btn-outline" data-del-row>حذف</button></td></tr></template><button type="button" class="btn btn-outline" data-add-row="proftpl" data-target="profbody">إضافة مهنة</button><button class="btn btn-red">حفظ المخزون</button></form></div><br><div class="card"><h3>بحث المخزون</h3><input placeholder="بحث برقم التأشيرة أو السجل أو المورد أو المهنة" oninput="filterRows(this,'visarow')"><table class="table"><tr><th>رقم التأشيرة</th><th>السجل</th><th>المورد</th><th>الشركة</th><th>النوع</th><th>السعر</th><th>المهن</th></tr><?php foreach(q('SELECT b.*,c.name currency_name FROM visa_batches b LEFT JOIN currencies c ON c.id=b.currency_id WHERE b.branch_id=? ORDER BY b.id DESC',[branch_id()])->fetchAll() as $b):$ps=q('SELECT * FROM visa_professions WHERE batch_id=? AND branch_id=?',[$b['id'],branch_id()])->fetchAll();?><tr class="visarow"><td><?=e($b['visa_number'])?></td><td><?=e($b['registry_number'])?></td><td><?=e($b['supplier_name'])?></td><td><?=e($b['company_name'])?></td><td><?=e($b['visa_type'])?></td><td><?=money($b['price']).' '.e($b['currency_name']??'')?></td><td><?php foreach($ps as $p){$available=max(0,(int)$p['quantity']-(int)$p['used_qty']);$notAuth=max(0,(int)$p['quantity']-(int)$p['authorized_qty']);echo e($p['profession_name']).': '.(int)$p['quantity'].' | متاح للعملاء '.$available.' | غير مفوض '.$notAuth.' | مفوض '.(int)$p['authorized_qty'].' | منزل لعملاء '.(int)$p['used_qty'].'<br>';}?></td></tr><?php endforeach;?></table></div><?php render('مخزون التأشيرات',ob_get_clean(),'queries');}
function act_visa_save(){$miss=[];foreach(['visa_number'=>'رقم التأشيرة','visa_type'=>'نوع التأشيرة','total_quantity'=>'العدد الإجمالي'] as $k=>$v){if(trim($_POST[$k]??'')==='')$miss[]=$v;}if($miss){flash('يرجى إكمال: '.implode('، ',$miss),'err');go('visa_stock');}$sup=null;if($_POST['supplier_id']){$sup=q('SELECT * FROM suppliers WHERE id=? AND branch_id=?',[$_POST['supplier_id'],branch_id()])->fetch();if(!$sup){v13_notice('لا يمكن حفظ المخزون','المورد المحدد غير موجود في هذا الفرع.','visa_stock');return;}}q('INSERT INTO visa_batches(supplier_id,supplier_name,visa_number,registry_number,company_name,visa_type,price,currency_id,total_quantity,notes,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,NOW(),?)',[$_POST['supplier_id']?:null,$sup['name']??'',$_POST['visa_number'],$_POST['registry_number'],$_POST['company_name'],$_POST['visa_type'],$_POST['price']?:0,$_POST['currency_id']?:2,$_POST['total_quantity'],$_POST['notes']??'',user()['id'],branch_id()]);$bid=db()->lastInsertId();
    $visaCost=(float)($_POST['price']?:0)*(int)($_POST['total_quantity']?:0);$visaCur=(int)($_POST['currency_id']?:2);
    if($sup && $visaCost>0){
        if(empty($sup['account_id'])){$aid=add_account('مورد',$sup['name']??'مورد','credit',$visaCur);q('UPDATE suppliers SET account_id=? WHERE id=? AND branch_id=?',[$aid,$sup['id'],branch_id()]);$sup['account_id']=$aid;}
        $desc='شراء مخزون تأشيرات من المورد '.($sup['name']??'').' | رقم التأشيرة: '.($_POST['visa_number']??'').' | رقم السجل: '.($_POST['registry_number']??'').' | الشركة: '.($_POST['company_name']??'').' | نوع التأشيرة: '.($_POST['visa_type']??'').' | العدد: '.($_POST['total_quantity']??0).' | سعر الواحدة: '.($_POST['price']??0).' '.currency_code($visaCur).' | الإجمالي: '.$visaCost.' '.currency_code($visaCur);
        $stockAid=(int)(q('SELECT account_id FROM branch_accounts WHERE branch_id=? AND account_key=?',[branch_id(),'visa_stock'])->fetchColumn()?:ensure_named_account('مخزون التأشيرات '.branch_name(),'أصول','debit','الأصول المتداولة'));
        $jid=create_journal_with_lines(next_code('JV'),'شراء مخزون تأشيرات',$desc,$visaCur,[
            ['account_id'=>$stockAid,'debit'=>$visaCost,'credit'=>0,'currency_id'=>$visaCur,'description'=>$desc],
            ['account_id'=>(int)$sup['account_id'],'debit'=>0,'credit'=>$visaCost,'currency_id'=>$visaCur,'description'=>$desc]
        ]);
        q('UPDATE visa_batches SET notes=CONCAT(COALESCE(notes,""),?) WHERE id=? AND branch_id=?',["
قيد شراء المخزون: ".$jid,$bid,branch_id()]);
    }$sum=0;foreach($_POST['prof_name']??[] as $k=>$pn){$q=(int)($_POST['prof_qty'][$k]??0);if(trim($pn)&&$q>0){$sum+=$q;q('INSERT INTO visa_professions(batch_id,profession_name,quantity,created_at,branch_id) VALUES(?,?,?,NOW(),?)',[$bid,$pn,$q,branch_id()]);}}flash($sum==(int)$_POST['total_quantity']?'تم حفظ المخزون':'تم الحفظ مع تنبيه: مجموع المهن لا يساوي الإجمالي',$sum==(int)$_POST['total_quantity']?'ok':'err');go('visa_stock');}

