function act_authorize_save(){ $qtys=$_POST['qty']??[]; $selected=0; foreach($qtys as $qv){ if((int)$qv>0)$selected++; } if($selected<1){flash('لم يتم تحديد أي تأشيرة للتفويض','err');go('visa_status');} if(trim($_POST['auth_no']??'')===''){v13_notice('رقم التفويض مطلوب','لا يمكن تفويض المحدد قبل إدخال رقم التفويض.','visa_status');return;} $officeId=(int)($_POST['office_id']??0);$officeOk=q('SELECT id FROM offices WHERE id=? AND branch_id=?',[$officeId,branch_id()])->fetchColumn();if(!$officeOk){v13_notice('لا يمكن التفويض','المكتب المخلص غير موجود في هذا الفرع.','visa_status');return;} foreach($qtys as $pid=>$qty){$qty=(int)$qty;if($qty<=0)continue;$p=q('SELECT * FROM visa_professions WHERE id=? AND branch_id=?',[$pid,branch_id()])->fetch();if(!$p){flash('لا يمكن تفويض تأشيرة من فرع آخر','err');continue;}$notAuth=max(0,(int)$p['quantity']-(int)$p['authorized_qty']);if($qty>$notAuth){flash('كمية التفويض أكبر من غير المفوض لبعض المهن','err');continue;}q('INSERT INTO visa_authorizations(batch_id,profession_id,office_id,auth_no,quantity,notes,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,?,?,?)',[$p['batch_id'],$pid,$officeId,$_POST['auth_no'],$qty,$_POST['notes'],user()['id'],now(),branch_id()]);q('UPDATE visa_professions SET authorized_qty=authorized_qty+? WHERE id=? AND branch_id=?',[$qty,$pid,branch_id()]);}flash('تم التفويض بدون قيد مالي على المكتب');go('visa_status');}
function page_transactions(){
    $year=date('Y');$from=$_GET['date_from']??($year.'-01-01');$to=$_GET['date_to']??($year.'-12-31');
    $services=q('SELECT * FROM services ORDER BY name')->fetchAll();$statuses=q('SELECT id,service_id,name FROM service_statuses ORDER BY service_id,sort_order,name')->fetchAll();$customers=q('SELECT id,name FROM customers WHERE branch_id=? ORDER BY name',[branch_id()])->fetchAll();$suppliers=q('SELECT id,name FROM suppliers WHERE branch_id=? ORDER BY name',[branch_id()])->fetchAll();$agents=q('SELECT id,name FROM agents WHERE branch_id=? ORDER BY name',[branch_id()])->fetchAll();$offices=q('SELECT id,name FROM offices WHERE branch_id=? ORDER BY name',[branch_id()])->fetchAll();
    $sql='SELECT t.*,c.name customer,c.passport_no,c.phone,c.account_id customer_account_id,s.name service,ss.name status,sup.name supplier,ag.name agent,o.name office,cur.code currency_code,cur.name currency_name FROM transactions t JOIN customers c ON c.id=t.customer_id JOIN services s ON s.id=t.service_id LEFT JOIN service_statuses ss ON ss.id=t.status_id LEFT JOIN suppliers sup ON sup.id=t.supplier_id LEFT JOIN agents ag ON ag.id=t.agent_id LEFT JOIN offices o ON o.id=t.office_id LEFT JOIN currencies cur ON cur.id=t.currency_id WHERE t.transaction_date BETWEEN ? AND ? AND t.branch_id=? ORDER BY t.id DESC LIMIT 1500';
    $rows=q($sql,[$from,$to,branch_id()])->fetchAll();
    $accIds=array_values(array_unique(array_filter(array_map(function($r){return (int)($r['customer_account_id']??0);},$rows))));
    $balMap=[];
    if($accIds){$in=implode(',',array_fill(0,count($accIds),'?'));foreach(q('SELECT account_id,currency_id,COALESCE(SUM(debit-credit),0) bal FROM ledger_entries WHERE branch_id=? AND account_id IN ('.$in.') GROUP BY account_id,currency_id',array_merge([branch_id()],$accIds))->fetchAll() as $br){$balMap[(int)$br['account_id']][(int)$br['currency_id']]=(float)$br['bal'];}}
    $currencies=q('SELECT id,name,code FROM currencies ORDER BY id')->fetchAll();
    ob_start();?>
