<div class="card table-scroll-x" id="transactionsTableCard"><table class="table data-grid-v13 resizable-table-v13 transactions-table-v22" id="transactionsTable"><thead><tr><th data-col="id">#</th><th data-col="customer">العميل</th><th data-col="passport">الوثيقة</th><th data-col="phone">الهاتف</th><th data-col="service">الخدمة</th><th data-col="status">الحالة</th><th data-col="company">الشركة/المهنة</th><th data-col="visa_type">نوع التأشيرة</th><th data-col="visa">رقم التأشيرة</th><th data-col="registry">السجل</th><th data-col="supplier">المورد</th><th data-col="agent">الوكيل</th><th data-col="office">المكتب المخلص</th><th data-col="amount">المبلغ</th><th data-col="remain">المتبقي على العميل</th><th data-col="actions">إجراء</th></tr></thead><tbody><?php foreach($rows as $t):$acc=(int)($t['customer_account_id']??0);$curBals=$balMap[$acc]??[];$nonZeroCurrencies=[];$remainParts=[];$bal=0;foreach($curBals as $cid=>$cv){$bal+=(float)$cv;if(abs((float)$cv)>0.001){$nonZeroCurrencies[]=(string)$cid;$cinfo=array_values(array_filter($currencies,function($cc) use($cid){return (int)$cc['id']===(int)$cid;}));$remainParts[]=money($cv).' '.e($cinfo[0]['code']??$cid);}}$remain=($nonZeroCurrencies?'has':'zero');$remainCurrencyList=implode(',',$nonZeroCurrencies);$remainText=$remainParts?implode(' / ',$remainParts):'0';?><tr class="txrow" data-service="<?=e($t['service_id'])?>" data-status="<?=e($t['status_id']?:0)?>" data-customer="<?=e($t['customer_id'])?>" data-supplier="<?=e($t['supplier_id']?:0)?>" data-agent="<?=e($t['agent_id']?:0)?>" data-office="<?=e($t['office_id']?:0)?>" data-sale="<?=e($t['sale_type']?:'مباشر')?>" data-visa_type="<?=e($t['visa_type']?:'0')?>" data-currency="<?=e($t['currency_id']?:1)?>" data-remain-currencies="<?=e($remainCurrencyList)?>" data-remain="<?=e($remain)?>"><td data-col="id"><?=$t['id']?></td><td data-col="customer"><a href="<?=route('customer_profile',['id'=>$t['customer_id']])?>"><?=e($t['customer'])?></a></td><td data-col="passport"><?=e($t['passport_no'])?></td><td data-col="phone"><?=e($t['phone'])?></td><td data-col="service"><?=e($t['service'])?></td><td data-col="status"><span class="badge blue"><?=e($t['status']?:'بدون حالة')?></span></td><td data-col="company" class="clip-cell"><?=e($t['company_name'])?></td><td data-col="visa_type"><?=e($t['visa_type']?:'—')?></td><td data-col="visa"><?=e($t['visa_number'])?></td><td data-col="registry"><?=e($t['registry_number'])?></td><td data-col="supplier"><?=e($t['supplier']?:'—')?></td><td data-col="agent"><?=e($t['agent']?:'مباشر')?></td><td data-col="office"><?=e($t['office']?:'—')?></td><td data-col="amount"><?=money($t['price']).' '.e($t['currency_code']??'')?></td><td data-col="remain"><?=$remainText?></td><td data-col="actions"><button class="btn btn-sm btn-outline" onclick="v22TxEdit('<?=route('transaction_form',['id'=>$t['id']])?>',<?=can_edit('transactions.edit')?'true':'false'?>)">تعديل</button><button class="btn btn-sm btn-outline" onclick="v22ConfirmGo('هل أنت متأكد من عمل مردود لهذه المعاملة؟','<?=route('refund',['id'=>$t['id']])?>')">مردود</button><button class="btn btn-sm btn-red" onclick="openDeliveryModalV22(<?=$t['id']?>,'<?=e($t['customer'])?>',<?=$t['customer_id']?>,'<?=e($t['service'])?>',<?=json_encode($bal)?>)">تسليم</button></td></tr><?php endforeach;?></tbody></table></div>
