function act_transaction_save(){$id=(int)($_POST['id']??0);$required=['customer_id'=>'العميل','service_id'=>'الخدمة','price'=>'السعر','currency_id'=>'عملة السعر','transaction_date'=>'التاريخ'];$miss=[];foreach($required as $k=>$v){if(trim($_POST[$k]??'')==='')$miss[]=$v;}if($miss){flash('يرجى إكمال البيانات التالية: '.implode('، ',$miss),'err');go('transaction_form',$id?['id'=>$id]:[]);} $c=q('SELECT * FROM customers WHERE id=? AND branch_id=?',[$_POST['customer_id'],branch_id()])->fetch();$s=q('SELECT * FROM services WHERE id=?',[$_POST['service_id']])->fetch();if(!$c||!$s){flash('العميل أو الخدمة غير صحيحة','err');go('transaction_form',$id?['id'=>$id]:[]);} if($id&&!q('SELECT id FROM transactions WHERE id=? AND branch_id=?',[$id,branch_id()])->fetchColumn()){flash('لا يمكن تعديل معاملة تابعة لفرع آخر','err');go('transactions');} if(!ensure_same_branch_v42($c['branch_id']??branch_id(),'العميل'))go('transactions');/* V16: خدمة الفيز يمكن حفظها بدون اختيار من المخزون، والاختيار يبقى اختياري حسب طلب المستخدم */ $st=q('SELECT * FROM service_statuses WHERE service_id=? ORDER BY sort_order LIMIT 1',[$s['id']])->fetch();$oldVisa=$id?(q('SELECT visa_profession_id FROM transactions WHERE id=? AND branch_id=?',[$id,branch_id()])->fetchColumn()?:0):0;$p=null;if(!empty($_POST['visa_profession_id'])){$p=q('SELECT p.*,b.visa_number,b.registry_number,b.company_name,b.visa_type,b.supplier_id,b.price,b.currency_id purchase_currency_id,b.id batch_id FROM visa_professions p JOIN visa_batches b ON b.id=p.batch_id WHERE p.id=? AND p.branch_id=?',[$_POST['visa_profession_id'],($c['branch_id']??branch_id())])->fetch(); if(!$p){flash('التأشيرة المختارة غير موجودة','err');go('transaction_form',$id?['id'=>$id]:[]);} if(((int)$oldVisa!==(int)$_POST['visa_profession_id'])&&((int)$p['quantity']-(int)$p['used_qty'])<=0){flash('هذه التأشيرة غير متاحة أو مستخدمة','err');go('transaction_form',$id?['id'=>$id]:[]);} if((float)$_POST['price']<(float)$p['price']) flash('تنبيه: سعر البيع أقل من سعر الشراء','err');}$sale=(in_array($c['customer_source'],['وكيل','تبع وكيل'])&&$c['agent_id'])?'تبع وكيل':'مباشر';$agent=$sale==='تبع وكيل'?$c['agent_id']:null;$comm=$sale==='تبع وكيل'?(float)($_POST['agent_commission']?:0):0;$cur=(int)($_POST['currency_id']?:2);if($id){$old=['visa_profession_id'=>$oldVisa];q('UPDATE transactions SET customer_id=?,service_id=?,status_id=COALESCE(status_id,?),visa_batch_id=?,visa_profession_id=?,visa_number=?,registry_number=?,company_name=?,visa_type=?,supplier_id=?,agent_id=?,sale_type=?,agent_commission=?,price=?,currency_id=?,transaction_date=?,notes=? WHERE id=? AND branch_id=?',[$c['id'],$s['id'],$st['id']??null,$p['batch_id']??null,$_POST['visa_profession_id']?:null,$p['visa_number']??'',$p['registry_number']??'',$p['company_name']??'',$p['visa_type']??'',$p['supplier_id']??null,$agent,$sale,$comm,$_POST['price']?:0,$cur,$_POST['transaction_date'],$_POST['notes']??'',$id,branch_id()]);if($old&&$old['visa_profession_id']!=$_POST['visa_profession_id']){if($old['visa_profession_id'])q('UPDATE visa_professions SET used_qty=GREATEST(used_qty-1,0) WHERE id=? AND branch_id=?',[$old['visa_profession_id'],branch_id()]);if($p)q('UPDATE visa_professions SET used_qty=used_qty+1 WHERE id=? AND branch_id=?',[$p['id'],branch_id()]);}q('DELETE FROM ledger_entries WHERE source_type=? AND source_id=? AND branch_id=?',['transaction',$id,branch_id()]);$saleDesc='إيراد خدمة '.$s['name'].' للعميل '.$c['name'];ledger($c['account_id'],'transaction',$id,$saleDesc,$_POST['price']?:0,0,$cur);$incomeAcc=branch_account_id_v46('income',$c['branch_id']??branch_id())?:ensure_named_account('إيرادات الخدمات','إيرادات','credit','الإيرادات');ledger($incomeAcc,'transaction',$id,$saleDesc,0,$_POST['price']?:0,$cur);ensure_supplier_ledger_for_transaction($id);flash('تم تعديل المعاملة');go('transactions');}q('INSERT INTO transactions(customer_id,service_id,status_id,visa_batch_id,visa_profession_id,visa_number,registry_number,company_name,visa_type,supplier_id,agent_id,sale_type,agent_commission,price,currency_id,transaction_date,notes,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW(),?)',[$c['id'],$s['id'],$st['id']??null,$p['batch_id']??null,$_POST['visa_profession_id']?:null,$p['visa_number']??'',$p['registry_number']??'',$p['company_name']??'',$p['visa_type']??'',$p['supplier_id']??null,$agent,$sale,$comm,$_POST['price']?:0,$cur,$_POST['transaction_date'],$_POST['notes']??'',user()['id'],$c['branch_id']??branch_id()]);$tid=db()->lastInsertId();$saleDesc='إيراد خدمة '.$s['name'].' للعميل '.$c['name'];ledger($c['account_id'],'transaction',$tid,$saleDesc,$_POST['price']?:0,0,$cur);$incomeAcc=branch_account_id_v46('income',$c['branch_id']??branch_id())?:ensure_named_account('إيرادات الخدمات','إيرادات','credit','الإيرادات');ledger($incomeAcc,'transaction',$tid,$saleDesc,0,$_POST['price']?:0,$cur); if($p)q('UPDATE visa_professions SET used_qty=used_qty+1 WHERE id=? AND branch_id=?',[$p['id'],branch_id()]); ensure_supplier_ledger_for_transaction($tid); if($agent&&$comm>0){$a=q('SELECT * FROM agents WHERE id=? AND branch_id=?',[$agent,branch_id()])->fetch(); if($a){if(!$a['account_id']){$aid=add_account_for_branch_v49(branch_id(),'وكيل',$a['name'],'credit',$cur);q('UPDATE agents SET account_id=? WHERE id=? AND branch_id=?',[$aid,$a['id'],branch_id()]);$a['account_id']=$aid;} $commAcc=branch_expense_account_v49('عمولات وكلاء');$descComm='عمولة وكيل عن العميل '.$c['name'];create_journal_with_lines(next_code('JV'),'عمولة وكيل',$descComm,$cur,[['account_id'=>$commAcc,'debit'=>$comm,'credit'=>0,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$descComm],['account_id'=>$a['account_id'],'debit'=>0,'credit'=>$comm,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$descComm]]);}} flash('تم حفظ المعاملة');go('transactions');}


function supplier_visa_cost_amount($transaction){
    $cost=(float)($transaction['purchase_price']??0);
    if($cost<=0)$cost=(float)($transaction['visa_purchase_price']??0);
    if($cost<=0)$cost=(float)($transaction['supplier_price']??0);
    return $cost;
}
function ensure_supplier_ledger_for_transaction($tid){
    $tid=(int)$tid;if(!$tid)return 0;
    try{ensure_column_exists('transactions','supplier_journal_id','INT NULL');}catch(Throwable $e){}
    $t=q("SELECT t.*,c.name customer,s.name service,sup.name supplier_name,sup.account_id supplier_account_id,vb.price purchase_price,vb.currency_id purchase_currency_id,vb.visa_number batch_visa_number,vb.registry_number batch_registry_number,vb.company_name batch_company_name,vb.visa_type batch_visa_type FROM transactions t JOIN customers c ON c.id=t.customer_id JOIN services s ON s.id=t.service_id LEFT JOIN suppliers sup ON sup.id=t.supplier_id LEFT JOIN visa_batches vb ON vb.id=t.visa_batch_id WHERE t.id=?",[$tid])->fetch();
    if(!$t || empty($t['visa_batch_id']) || !empty($t['supplier_journal_id']))return 0;
    $branchId=(int)($t['branch_id']??branch_id());
    $cost=supplier_visa_cost_amount($t);$cur=(int)($t['purchase_currency_id']?:$t['currency_id']?:2);
    if($cost<=0)return 0;
    $stockAcc=(int)(q('SELECT account_id FROM branch_accounts WHERE branch_id=? AND account_key=?',[$branchId,'visa_stock'])->fetchColumn()?:ensure_named_account('مخزون التأشيرات '.branch_name($branchId),'أصول','debit','الأصول المتداولة'));
    try{q('UPDATE accounts SET branch_id=? WHERE id=?',[$branchId,$stockAcc]);}catch(Throwable $e){}
    $expenseAcc=ensure_named_account('تكلفة التأشيرات المباعة - '.branch_name($branchId),'مصروفات','debit','المصروفات');try{q('UPDATE accounts SET branch_id=? WHERE id=?',[$branchId,$expenseAcc]);}catch(Throwable $e){}
    $desc='تحميل تكلفة تأشيرة مباعة للعميل '.$t['customer'].' | الخدمة: '.$t['service'].' | المورد: '.($t['supplier_name']?:'غير محدد').' | رقم التأشيرة: '.($t['visa_number']?:$t['batch_visa_number']).' | رقم السجل: '.($t['registry_number']?:$t['batch_registry_number']).' | الشركة: '.($t['company_name']?:$t['batch_company_name']).' | نوع التأشيرة: '.($t['visa_type']?:$t['batch_visa_type']).' | تكلفة الشراء: '.$cost.' '.currency_code($cur).' | سعر البيع للعميل: '.$t['price'].' '.currency_code($t['currency_id']);
    $jid=create_journal_with_lines(next_unique_code_v52('JV','journal_entries','entry_no',$branchId),'تكلفة تأشيرة مباعة',$desc,$cur,[
        ['account_id'=>$expenseAcc,'debit'=>$cost,'credit'=>0,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc],
        ['account_id'=>$stockAcc,'debit'=>0,'credit'=>$cost,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc]
    ],$branchId,$t['transaction_date']??null);
    q('UPDATE transactions SET supplier_journal_id=? WHERE id=?',[$jid,$tid]);
    return $jid;
}
function backfill_supplier_ledgers($limit=100){
    try{ensure_column_exists('transactions','supplier_journal_id','INT NULL');}catch(Throwable $e){}
    try{$rows=q('SELECT id FROM transactions WHERE supplier_id IS NOT NULL AND supplier_id<>0 AND (supplier_journal_id IS NULL OR supplier_journal_id=0) AND visa_batch_id IS NOT NULL ORDER BY id ASC LIMIT '.(int)$limit)->fetchAll();foreach($rows as $r)ensure_supplier_ledger_for_transaction($r['id']);}catch(Throwable $e){}
}

