<?php $sql='SELECT ot.*,c.name customer,o.name office,t.visa_number,t.registry_number,t.company_name,t.service_id,s.name service FROM office_transfers ot LEFT JOIN customers c ON c.id=ot.customer_id LEFT JOIN offices o ON o.id=ot.office_id LEFT JOIN transactions t ON t.id=ot.transaction_id LEFT JOIN services s ON s.id=t.service_id WHERE COALESCE(ot.is_reversed,0)=0 AND ot.branch_id=?';$args=[branch_id()];if($revQ!==''){$sql.=' AND (c.name LIKE ? OR o.name LIKE ? OR t.visa_number LIKE ? OR t.registry_number LIKE ? OR t.company_name LIKE ? OR ot.description LIKE ? OR s.name LIKE ?)';for($i=0;$i<7;$i++)$args[]=$revLike;}$sql.=' ORDER BY ot.id DESC LIMIT 300';foreach(q($sql,$args)->fetchAll() as $ot):?><tr class="reverseRow" data-office="<?=e($ot['office_id'])?>" data-service="<?=e($ot['service_id'])?>"><td><input type="checkbox" name="ids[]" value="<?=$ot['id']?>"></td><td><?=e($ot['customer'])?></td><td><?=e($ot['office'])?></td><td><?=e($ot['service'])?></td><td><?=e($ot['visa_number'])?></td><td><?=e($ot['registry_number'])?></td><td><?=e($ot['company_name'])?></td><td><?=money($ot['price'])?></td><td><?=e($ot['description'])?></td><td><?=e($ot['created_at'])?></td></tr><?php endforeach;?></table><button class="btn btn-outline">إلغاء الترحيل للمحدد</button></form></div><?php render('ترحيل المعاملات',ob_get_clean(),'queries');}

function act_transfer_save(){
    if(empty($_POST['ids'])){v13_notice('لا يمكن الترحيل','لم يتم تحديد أي معاملة للترحيل.','transfer');return;}
    $o=q('SELECT * FROM offices WHERE id=? AND branch_id=?',[$_POST['office_id'],branch_id()])->fetch();
    if(!$o){v13_notice('لا يمكن الترحيل','المكتب المخلص غير موجود في هذا الفرع.','transfer');return;}
    if(!$o['account_id']){$aid=add_account_for_branch_v49(branch_id(),'مكتب مخلص',$o['name'],'credit',1);q('UPDATE offices SET account_id=? WHERE id=? AND branch_id=?',[$aid,$o['id'],branch_id()]);$o['account_id']=$aid;}
    validate_account_write_v48($o['account_id'],'حساب المكتب المخلص','transfer');
    try{ensure_column_exists('office_transfers','journal_id','INT NULL');}catch(Throwable $e){}
    $costAcc=branch_expense_account_v49('تكلفة مكاتب مخلصة');
    foreach($_POST['ids']??[] as $id){
        $t=q('SELECT t.*,c.name customer,c.id cid FROM transactions t JOIN customers c ON c.id=t.customer_id WHERE t.id=? AND t.branch_id=? AND t.is_relayed=0',[$id,branch_id()])->fetch();if(!$t)continue;
        $amt=(float)($_POST['price']??0);$cur=(int)($_POST['currency_id']?:1);if($amt<=0)continue;
        $desc=($_POST['description']?:'ترحيل معاملة إلى مكتب مخلص').' - العميل '.$t['customer'];
        q('INSERT INTO office_transfers(office_id,transaction_id,customer_id,price,currency_id,description,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,?,NOW(),?)',[$o['id'],$id,$t['cid'],$amt,$cur,$desc,user()['id'],($t['branch_id']??branch_id())]);$oid=db()->lastInsertId();
        $jid=create_journal_with_lines(next_code('JV'),'ترحيل معاملة لمكتب مخلص',$desc,$cur,[
            ['account_id'=>$costAcc,'debit'=>$amt,'credit'=>0,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc.' - تكلفة مكتب مخلص'],
            ['account_id'=>$o['account_id'],'debit'=>0,'credit'=>$amt,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc.' - مستحق للمكتب المخلص']
        ]);
        try{q('UPDATE office_transfers SET journal_id=? WHERE id=? AND branch_id=?',[$jid,$oid,branch_id()]);}catch(Throwable $e){}
        q('UPDATE transactions SET is_relayed=1,office_id=? WHERE id=? AND branch_id=?',[$o['id'],$id,branch_id()]);
    }
    flash('تم الترحيل بقيد محاسبي مزدوج: تكلفة مكتب مخلص مقابل حساب المكتب المخلص');go('transfer');}
function act_transfer_reverse(){
    if(!can_edit('transfer.edit')){flash('لا تملك صلاحية التعديل','err');go('transfer');}
    $ids=array_values(array_filter($_POST['ids']??[])); if(!$ids){v13_notice('لا يمكن إلغاء الترحيل','لم يتم تحديد ترحيل.','transfer');return;}
    $discountType=$_POST['discount_type']??'none';$discountAmount=(float)($_POST['discount_amount']??0);$discountCur=(int)($_POST['discount_currency_id']??1);
    $rows=[];foreach($ids as $id){$ot=q('SELECT ot.*,c.name customer,o.name office,o.account_id office_account FROM office_transfers ot LEFT JOIN customers c ON c.id=ot.customer_id LEFT JOIN offices o ON o.id=ot.office_id WHERE ot.id=? AND ot.branch_id=? AND COALESCE(ot.is_reversed,0)=0',[$id,branch_id()])->fetch();if($ot)$rows[]=$ot;}
    if(!$rows){v13_notice('لا يمكن إلغاء الترحيل','كل الترحيلات المحددة ملغاة أو غير موجودة.','transfer');return;}
    $count=max(1,count($rows));$allNames=implode('، ',array_map(fn($r)=>$r['customer'],$rows));$officeName=$rows[0]['office']??'';$tpl=$_POST['reverse_description']?:'إلغاء ترحيل معاملة - العميل {client} إلى المكتب {office}';$baseDesc=str_replace(['{client}','{office}'],[$allNames,$officeName],$tpl);
    $costAcc=branch_expense_account_v49('تكلفة مكاتب مخلصة');$discountIncome=branch_income_account_v49('خصومات إلغاء الترحيل');
    $lines=[];
    foreach($rows as $r){
        if(empty($r['office_account'])){ $aid=add_account_for_branch_v49(branch_id(),'مكتب مخلص',$r['office']?:'مكتب مخلص','credit',1); q('UPDATE offices SET account_id=? WHERE id=? AND branch_id=?',[$aid,$r['office_id'],branch_id()]); $r['office_account']=$aid; }
        validate_account_write_v48($r['office_account'],'حساب المكتب المخلص','transfer');
        $desc=str_replace(['{client}','{office}'],[$r['customer'],$r['office']],$tpl);$amt=(float)$r['price'];$cur=(int)$r['currency_id'];
        $disc=0;if($discountType==='total' && $discountAmount>0)$disc=round($discountAmount/$count,2);elseif($discountType==='per_person' && $discountAmount>0)$disc=$discountAmount;
        if($disc>0 && $discountCur!==$cur){v13_notice('لا يمكن إلغاء الترحيل','عملة الخصم يجب أن تكون نفس عملة الترحيل حتى يبقى القيد متوازناً لكل عملة.','transfer');return;}
        if($amt>0){$net=max(0,$amt-$disc);$lines[]=['account_id'=>$r['office_account'],'debit'=>$amt,'credit'=>0,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc.' - إقفال مستحق المكتب المخلص'];if($net>0)$lines[]=['account_id'=>$costAcc,'debit'=>0,'credit'=>$net,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc.' - عكس تكلفة مكتب مخلص'];if($disc>0)$lines[]=['account_id'=>$discountIncome,'debit'=>0,'credit'=>$disc,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc.' - خصم عند إلغاء الترحيل'];}
    }
    $jid=create_journal_with_lines(next_code('JV'),'إلغاء ترحيل',$baseDesc,1,$lines);
    foreach($rows as $r){q('UPDATE office_transfers SET is_reversed=1,reverse_journal_id=?,reverse_discount=?,reverse_currency_id=?,reverse_note=? WHERE id=? AND branch_id=?',[$jid,($discountType==='total'&&$discountAmount>0)?round($discountAmount/$count,2):(($discountType==='per_person')?$discountAmount:0),$discountCur,$baseDesc,$r['id'],branch_id()]);q('UPDATE transactions SET is_relayed=0,office_id=NULL WHERE id=? AND branch_id=?',[$r['transaction_id'],branch_id()]);}
    flash('تم إلغاء الترحيل بقيد عكسي متوازن');go('journal_view',['id'=>$jid]);}
function page_refund(){$id=(int)$_GET['id'];$t=q('SELECT t.*,c.name customer FROM transactions t JOIN customers c ON c.id=t.customer_id WHERE t.id=? AND t.branch_id=?',[$id,branch_id()])->fetch();if(!$t){flash('المعاملة غير موجودة في هذا الفرع','err');go('transactions');}ob_start();?><div class="page-title"><h2>عمل مردود للعميل</h2></div><div class="card"><form method="post" action="<?=route('refund_save')?>"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="id" value="<?=$id?>"><p>العميل: <b><?=e($t['customer'])?></b> | المبلغ: <?=money($t['price'])?></p><div class="form-grid"><div class="field"><label>خصم المكتب</label><input name="office_discount" type="number" step="0.01" value="0"></div><div class="field"><label>خصم المكتب المخلص</label><input name="clearing_discount" type="number" step="0.01" value="0"></div><div class="field"><label>البيان</label><input name="description" value="تم عمل مردود للعميل <?=e($t['customer'])?> عن الخدمة"></div></div><button class="btn btn-red">حفظ المردود</button></form></div><?php render('المردود',ob_get_clean(),'queries');}
function act_refund_save(){$t=q('SELECT t.*,c.name customer,c.account_id,o.account_id office_acc FROM transactions t JOIN customers c ON c.id=t.customer_id LEFT JOIN offices o ON o.id=t.office_id WHERE t.id=? AND t.branch_id=?',[$_POST['id'],branch_id()])->fetch();if(!$t){flash('المعاملة غير موجودة في هذا الفرع','err');go('transactions');}$officeDiscount=max(0,(float)($_POST['office_discount']??0));$clearingDiscount=max(0,(float)($_POST['clearing_discount']??0));$refund=max(0,(float)$t['price']-$officeDiscount-$clearingDiscount);$desc=trim($_POST['description']??'مردود معاملة للعميل '.$t['customer']);q('INSERT INTO refunds(transaction_id,customer_id,office_discount,clearing_discount,refund_amount,description,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,?,NOW(),?)',[$t['id'],$t['customer_id'],$officeDiscount,$clearingDiscount,$refund,$desc,user()['id'],branch_id()]);$rid=db()->lastInsertId();$cur=(int)$t['currency_id'];$salesReturnAcc=branch_expense_account_v49('مردودات العملاء');$lines=[];if($refund>0){$lines[]=['account_id'=>$salesReturnAcc,'debit'=>$refund,'credit'=>0,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc.' - مردود على إيراد العميل'];$lines[]=['account_id'=>$t['account_id'],'debit'=>0,'credit'=>$refund,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>$desc.' - تخفيض مديونية العميل'];}if($clearingDiscount>0 && !empty($t['office_acc'])){$lines[]=['account_id'=>$t['office_acc'],'debit'=>$clearingDiscount,'credit'=>0,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>'خصم مكتب مخلص ضمن مردود العميل '.$t['customer']];$lines[]=['account_id'=>$salesReturnAcc,'debit'=>0,'credit'=>$clearingDiscount,'currency_id'=>$cur,'target_currency_id'=>$cur,'exchange_rate'=>1,'description'=>'مقابلة خصم المكتب المخلص ضمن المردود'];}if($officeDiscount>0){$desc.=' | خصم مكتب/عميل غير مولد لقيد إضافي حتى لا تتضاعف مديونية العميل: '.money($officeDiscount).' '.currency_code($cur);}if($lines)create_journal_with_lines(next_code('JV'),'مردود عميل',$desc,$cur,$lines); if($t['visa_profession_id'])q('UPDATE visa_professions SET used_qty=GREATEST(used_qty-1,0) WHERE id=? AND branch_id=?',[$t['visa_profession_id'],branch_id()]);flash('تم المردود بقيد محاسبي متوازن ورجعت التأشيرة للمخزون إن وجدت');go('transactions');}
function page_delivery(){page_delivery_v52();return;$id=(int)$_GET['id'];$t=q('SELECT t.*,c.name customer,c.account_id,s.name service,o.name office FROM transactions t JOIN customers c ON c.id=t.customer_id JOIN services s ON s.id=t.service_id LEFT JOIN offices o ON o.id=t.office_id WHERE t.id=? AND t.branch_id=?',[$id,branch_id()])->fetch();if(!$t){flash('المعاملة غير موجودة في هذا الفرع','err');go('transactions');}$bal=balance($t['account_id']);ob_start();?><div class="page-title"><h2>سند تسليم</h2><button class="btn btn-red" data-print>طباعة</button></div><?php if(abs($bal)>0.001):?><div class="flash error">لا يمكن التسليم: على العميل رصيد <?=money($bal)?></div><?php endif;?><div class="receipt-page"><div class="receipt-title">سند تسليم</div><p style="font-size:20px;text-align:center">أنا / <?=e($t['customer'])?> استلمت الجواز جاهز من مكتب <?=e($t['office']?:setting('company_name',cfg('company_name')))?></p><div class="receipt-grid"><div class="receipt-row"><b>الخدمة:</b> <?=e($t['service'])?></div><div class="receipt-row"><b>رقم التأشيرة:</b> <?=e($t['visa_number'])?></div><div class="receipt-row"><b>رقم السجل:</b> <?=e($t['registry_number'])?></div><div class="receipt-row"><b>التاريخ:</b> <?=date('Y-m-d H:i')?></div></div><div class="signatures"><div class="signature">توقيع المستلم<div class="line"></div></div><div class="signature">توقيع الموظف<div class="line"></div></div><div class="signature">الختم<div class="line"></div></div></div><?php render('سند تسليم',ob_get_clean(),'queries');}
