NSERT INTO vouchers(type,voucher_no,voucher_date,voucher_time,amount,currency_id,exchange_rate,payment_method,cashbox_id,bank_id,transfer_no,party_name,description,red_note,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW(),?)',[$_POST['type'],$_POST['voucher_no'],$voucher_date,$voucher_time,$topAmt,$topCur,1,$_POST['payment_method'],$_POST['payment_method']==='نقداً'?($_POST['cashbox_id']?:null):null,$_POST['payment_method']==='حوالة'?($_POST['bank_id']?:null):null,$_POST['transfer_no']??'',$_POST['party_name'],$_POST['description'],$_POST['red_note']??'',user()['id'],branch_id()]);$vid=db()->lastInsertId();$payAcc=null;if(($_POST['payment_method']??'')==='نقداً'&&!empty($_POST['cashbox_id']))$payAcc=q('SELECT account_id FROM cashboxes WHERE id=? AND branch_id=?',[$_POST['cashbox_id'],branch_id()])->fetchColumn();if(($_POST['payment_method']??'')==='حوالة'&&!empty($_POST['bank_id']))$payAcc=q('SELECT account_id FROM banks WHERE id=? AND branch_id=?',[$_POST['bank_id'],branch_id()])->fetchColumn();if($payAcc){$pdesc=($_POST['type']==='قبض'?'استلام مبلغ من ':'صرف مبلغ إلى ').$_POST['party_name'];if($_POST['type']==='قبض')ledger($payAcc,'voucher',$vid,$pdesc,$topAmt,0,$topCur,1);else ledger($payAcc,'voucher',$vid,$pdesc,0,$topAmt,$topCur,1);}foreach($_POST['line_account'] as $k=>$aid){$amt=(float)($_POST['line_amount'][$k]??0);if($aid&&$amt>0){$cur=(int)($_POST['line_currency_id'][$k]??$topCur);$rate=(float)($_POST['line_exchange_rate'][$k]??fx_rate($topCur,$cur));$expected=fx_convert($topAmt,$topCur,$cur,$rate);$diff=$amt-$expected;$desc=trim($_POST['line_desc'][$k]??'')?:$_POST['description'];q('INSERT INTO voucher_lines(voucher_id,account_id,amount,description,currency_id,exchange_rate,result_amount,difference_amount,branch_id) VALUES(?,?,?,?,?,?,?,?,?)',[$vid,$aid,$amt,$desc,$cur,$rate,$amt,$diff,branch_id()]);if($_POST['type']==='قبض')ledger($aid,'voucher',$vid,$desc,0,$amt,$cur,$rate); else ledger($aid,'voucher',$vid,$desc,$amt,0,$cur,$rate);}}flash('تم حفظ السند');go('voucher_print',['id'=>$vid]);}
