function act_voucher_update(){
    verify();$id=(int)($_POST['id']??0);$old=q('SELECT * FROM vouchers WHERE id=?',[$id])->fetch();if(!$old){flash('السند غير موجود','err');go('statement');}
    $miss=[];$dt=str_replace('T',' ',$_POST['voucher_datetime']??'');$voucher_date=substr($dt,0,10);$voucher_time=substr($dt,11,8);if(strlen($voucher_time)<5)$voucher_time='00:00:00';
    foreach(['voucher_no'=>'رقم السند','voucher_datetime'=>'التاريخ والوقت','party_name'=>'استلمنا من/صرفنا إلى','amount_total'=>'المبلغ','currency_id'=>'عملة المبلغ','payment_method'=>'طريقة الدفع','description'=>'البيان الأساسي'] as $k=>$v){if(trim($_POST[$k]??'')==='')$miss[]=$v;}
    if(($_POST['payment_method']??'')==='نقداً' && empty($_POST['cashbox_id']))$miss[]='الصندوق'; if(($_POST['payment_method']??'')==='نقداً'&&!empty($_POST['cashbox_id'])&&!branch_record_allowed_v48('cashboxes',$_POST['cashbox_id'],'الصندوق'))$miss[]='الصندوق المحدد يتبع فرعاً آخر';
    if(($_POST['payment_method']??'')==='حوالة'){if(empty($_POST['bank_id']))$miss[]='البنك'; if(!empty($_POST['bank_id'])&&!branch_record_allowed_v48('banks',$_POST['bank_id'],'البنك'))$miss[]='البنك المحدد يتبع فرعاً آخر';if(empty($_POST['transfer_no']))$miss[]='رقم الحوالة';if(empty($_POST['transfer_date']))$miss[]='تاريخ الحوالة';}
    $topAmt=(float)($_POST['amount_total']??0);$topCur=(int)($_POST['currency_id']??2);$totalInTop=0;$valid=0;
    foreach($_POST['line_account']??[] as $k=>$aid){$amt=(float)($_POST['line_amount'][$k]??0);$cur=(int)($_POST['line_currency_id'][$k]??$topCur);$rate=(float)($_POST['line_exchange_rate'][$k]??fx_rate($topCur,$cur));if($aid||$amt>0){$valid++;if(!$aid)$miss[]='حساب السطر رقم '.($k+1); elseif(!account_write_allowed_v48($aid))$miss[]='حساب السطر رقم '.($k+1).' غير متاح لهذا الفرع';if($amt<=0)$miss[]='مبلغ السطر رقم '.($k+1);if(!$cur)$miss[]='عملة السطر رقم '.($k+1);if($cur!==$topCur && $rate<=0)$miss[]='صرف السطر رقم '.($k+1);$totalInTop += ($cur===$topCur?$amt:($rate>0?$amt/$rate:0));}}
    if($valid<1)$miss[]='سطر حساب واحد على الأقل';if(abs($totalInTop-$topAmt)>0.01)$miss[]='السند غير مكتمل: إجمالي السطور لا يساوي المبلغ';
    if($miss){flash('لا يمكن تعديل السند: '.implode('، ',$miss),'err');go('voucher_view',['id'=>$id]);}
    q('UPDATE vouchers SET type=?,voucher_no=?,voucher_date=?,voucher_time=?,amount=?,currency_id=?,payment_method=?,cashbox_id=?,bank_id=?,transfer_no=?,party_name=?,description=?,red_note=? WHERE id=?',[$_POST['type'],$_POST['voucher_no'],$voucher_date,$voucher_time,$topAmt,$topCur,$_POST['payment_method'],$_POST['payment_method']==='نقداً'?($_POST['cashbox_id']?:null):null,$_POST['payment_method']==='حوالة'?($_POST['bank_id']?:null):null,$_POST['transfer_no']??'',$_POST['party_name'],$_POST['description'],$_POST['red_note']??'',$id]);
    q('DELETE FROM voucher_lines WHERE voucher_id=?',[$id]);q('DELETE FROM ledger_entries WHERE source_type=? AND source_id=?',['voucher',$id]);
    $payAcc=null;if(($_POST['payment_method']??'')==='نقداً'&&!empty($_POST['cashbox_id']))$payAcc=q('SELECT account_id FROM cashboxes WHERE id=? AND branch_id=?',[$_POST['cashbox_id'],branch_id()])->fetchColumn();if(($_POST['payment_method']??'')==='حوالة'&&!empty($_POST['bank_id']))$payAcc=q('SELECT account_id FROM banks WHERE id=? AND branch_id=?',[$_POST['bank_id'],branch_id()])->fetchColumn();
    if($payAcc){$pdesc=($_POST['type']==='قبض'?'استلام مبلغ من ':'صرف مبلغ إلى ').$_POST['party_name'];if($_POST['type']==='قبض')ledger($payAcc,'voucher',$id,$pdesc,$topAmt,0,$topCur,1);else ledger($payAcc,'voucher',$id,$pdesc,0,$topAmt,$topCur,1);}
    foreach($_POST['line_account'] as $k=>$aid){$amt=(float)($_POST['line_amount'][$k]??0);if($aid&&$amt>0){$cur=(int)($_POST['line_currency_id'][$k]??$topCur);$rate=(float)($_POST['line_exchange_rate'][$k]??fx_rate($topCur,$cur));$expected=fx_convert($topAmt,$topCur,$cur,$rate);$diff=$amt-$expected;$desc=trim($_POST['line_desc'][$k]??'')?:$_POST['description'];q('INSERT INTO voucher_lines(voucher_id,account_id,amount,description,currency_id,exchange_rate,result_amount,difference_amount,branch_id) VALUES(?,?,?,?,?,?,?,?,?)',[$id,$aid,$amt,$desc,$cur,$rate,$amt,$diff,($old['branch_id']??branch_id())]);if($_POST['type']==='قبض')ledger($aid,'voucher',$id,$desc,0,$amt,$cur,$rate); else ledger($aid,'voucher',$id,$desc,$amt,0,$cur,$rate);}}
    flash('تم تعديل السند');go('voucher_view',['id'=>$id]);
}
