function act_journal_update(){verify();$id=(int)($_POST['id']??0);$old=q('SELECT * FROM journal_entries WHERE id=? AND branch_id=?',[$id,branch_id()])->fetch();if(!$old){flash('القيد غير موجود في هذا الفرع','err');go('statement');}$miss=[];foreach(['entry_no'=>'رقم القيد','entry_datetime'=>'التاريخ والوقت','journal_type'=>'نوع العملية','description'=>'البيان'] as $k=>$v){if(trim($_POST[$k]??'')==='')$miss[]=$v;}$review=(int)($_POST['review_currency_id']??1);$de=0;$cr=0;$valid=0;foreach($_POST['account_id']??[] as $k=>$aid){$d=(float)($_POST['debit'][$k]??0);$c=(float)($_POST['credit'][$k]??0);$cur=(int)($_POST['currency_id'][$k]??1);$target=(int)($_POST['target_currency_id'][$k]??$review);$rate=(float)($_POST['exchange_rate'][$k]??fx_rate($cur,$target));$amt=$d>0?$d:$c;if($aid||$amt>0){$valid++;if(!$aid)$miss[]='حساب السطر رقم '.($k+1); elseif(!account_write_allowed_v48($aid))$miss[]='حساب السطر رقم '.($k+1).' غير متاح لهذا الفرع';if($d>0&&$c>0)$miss[]='لا يجوز إدخال مدين ودائن في نفس السطر '.($k+1);if($d<=0&&$c<=0)$miss[]='مبلغ مدين أو دائن للسطر '.($k+1);if(!$cur||!$target)$miss[]='عملة السطر رقم '.($k+1);if($cur!==$target && $rate<=0)$miss[]='سعر التحويل للسطر '.($k+1);$toReview=fx_convert($amt,$cur,$review,null);if($d>0)$de+=$toReview;else $cr+=$toReview;}}if($valid<2)$miss[]='سطرين على الأقل';if($de<=0||$cr<=0)$miss[]='يجب وجود طرف مدين وطرف دائن';if(abs($de-$cr)>0.01)$miss[]='القيد غير متوازن حسب عملة المراجعة';if($miss){flash('لا يمكن تعديل القيد: '.implode('، ',$miss),'err');go('journal_view',['id'=>$id]);}$dt=str_replace('T',' ',$_POST['entry_datetime']);$entryDate=substr($dt,0,10);$entryTime=substr($dt,11,8);if(strlen($entryTime)<5)$entryTime='00:00:00';q('UPDATE journal_entries SET entry_no=?,entry_date=?,entry_time=?,journal_type=?,description=?,review_currency_id=? WHERE id=?',[$_POST['entry_no'],$entryDate,$entryTime,$_POST['journal_type'],$_POST['description'],$review,$id]);q('DELETE FROM journal_lines WHERE journal_id=?',[$id]);q('DELETE FROM ledger_entries WHERE source_type=? AND source_id=?',['journal',$id]);foreach($_POST['account_id'] as $k=>$aid){$d=(float)($_POST['debit'][$k]??0);$c=(float)($_POST['credit'][$k]??0);$cur=(int)($_POST['currency_id'][$k]??1);$target=(int)($_POST['target_currency_id'][$k]??$review);$rate=(float)($_POST['exchange_rate'][$k]??fx_rate($cur,$target));$amt=$d>0?$d:$c;if($aid&&($d>0||$c>0)){$result=fx_convert($amt,$cur,$target,$rate);$desc=trim($_POST['line_description'][$k]??'')?:$_POST['description'];q('INSERT INTO journal_lines(journal_id,account_id,debit,credit,currency_id,target_currency_id,exchange_rate,result_amount,description,branch_id) VALUES(?,?,?,?,?,?,?,?,?,?)',[$id,$aid,$d,$c,$cur,$target,$rate,$result,$desc,($old['branch_id']??branch_id())]);ledger_branch(($old['branch_id']??branch_id()),$aid,'journal',$id,$desc,$d,$c,$cur,fx_rate($cur,$review));}}flash('تم تعديل القيد');go('journal_view',['id'=>$id]);}

