$all=q('SELECT * FROM accounts WHERE branch_id IS NULL OR branch_id=0 OR branch_id=? ORDER BY account_no',[branch_id()])->fetchAll();$byParent=[];foreach($all as $a){$byParent[$a['parent_id']??0][]=$a;}$renderTree=function($parent=0,$level=0) use (&$renderTree,&$byParent){$html='';foreach($byParent[$parent]??[] as $a){$terminal=in_array($a['name'],terminal_account_group_names(),true);$has=!$terminal&&!empty($byParent[$a['id']]);$html.='<li data-id="'.e($a['id']).'" data-name="'.e($a['name']).'" data-type="'.e($a['type']).'"><button type="button" class="tree-toggle">'.($has?'+':'•').'</button><a href="'.route('accounts',['selected'=>$a['id']]).'">'.e($a['account_no'].' '.$a['name']).'</a>'.($has?'<ul class="tree-children hidden">'.$renderTree($a['id'],$level+1).'</ul>':'').'</li>';}return $html;};
