    $rows=q('SELECT t.*,c.name customer,c.customer_source,c.passport_no,s.name service,ss.name status,o.name office FROM transactions t JOIN customers c ON c.id=t.customer_id JOIN services s ON s.id=t.service_id LEFT JOIN service_statuses ss ON ss.id=t.status_id LEFT JOIN offices o ON o.id=t.office_id WHERE t.transaction_date BETWEEN ? AND ? AND t.branch_id=? ORDER BY t.id DESC LIMIT 1000',[$from,$to,branch_id()])->fetchAll();ob_start();?>
