function act_transaction_batch_status_update(){if(!can_edit('transactions.edit')){system_no_permission('transaction_status_batch');return;}$ids=$_POST['ids']??[];$status=(int)($_POST['status_id']??0);if(!$ids||!$status){flash('حدد معاملات وحالة جديدة','err');go('transaction_status_batch');}$in=implode(',',array_fill(0,count($ids),'?'));$rows=q("SELECT id,service_id FROM transactions WHERE branch_id=? AND id IN ($in)",array_merge([branch_id()],$ids))->fetchAll();$serviceIds=array_unique(array_column($rows,'service_id'));if(count($serviceIds)>1){v13_notice('لا يمكن تغيير الحالة','الخدمات المحددة من أكثر من نوع. اختر معاملات من نفس الخدمة.','transaction_status_batch');return;}$ok=q('SELECT id FROM service_statuses WHERE id=? AND service_id=?',[$status,$serviceIds[0]??0])->fetchColumn();if(!$ok){v13_notice('حالة غير متوافقة','الحالة المختارة لا تتبع الخدمة المحددة.','transaction_status_batch');return;}q("UPDATE transactions SET status_id=? WHERE branch_id=? AND id IN ($in)",array_merge([$status,branch_id()],$ids));flash('تم تغيير حالة المعاملات المحددة');go('transaction_status_batch');}
function page_profit_loss(){
    $year=date('Y');$from=$_GET['from']??($year.'-01-01');$to=$_GET['to']??($year.'-12-31');$selected=report_selected_currency_ids('cur');$view=$_GET['view']??'summary';$search=trim($_GET['q']??'');
    $viewRows=[['id'=>'summary','name'=>'ملخص'],['id'=>'detailed','name'=>'تفصيلي'],['id'=>'currency','name'=>'حسب العملة']];
    $sql='SELECT a.id,a.account_no,a.name,a.type,l.currency_id,COALESCE(SUM(l.debit),0) debit,COALESCE(SUM(l.credit),0) credit,COUNT(l.id) cnt FROM accounts a JOIN ledger_entries l ON l.account_id=a.id WHERE DATE(l.entry_date) BETWEEN ? AND ? AND l.currency_id IN ('.implode(',',array_fill(0,count($selected),'?')).') AND l.branch_id=? AND a.type IN (?,?) GROUP BY a.id,l.currency_id ORDER BY l.currency_id,a.type,a.account_no,a.name';
    $params=array_merge([$from,$to],$selected,[branch_id(),'إيرادات','مصروفات']);$raw=q($sql,$params)->fetchAll();$byCur=[];$metrics=[];
    foreach($selected as $cid){$byCur[$cid]=[];$metrics[$cid]=['rev'=>0,'exp'=>0,'net'=>0,'count'=>0];}
    foreach($raw as $r){if($search!=='' && mb_stripos($r['account_no'].' '.$r['name'].' '.$r['type'],$search)===false)continue;$cid=(int)$r['currency_id'];$isRev=$r['type']==='إيرادات';$amount=$isRev?((float)$r['credit']-(float)$r['debit']):((float)$r['debit']-(float)$r['credit']);$row=['id'=>$r['id'],'no'=>$r['account_no'],'name'=>$r['name'],'type'=>$r['type'],'revenue'=>$isRev?max(0,$amount):0,'expense'=>!$isRev?max(0,$amount):0,'net'=>$isRev?$amount:-$amount,'cnt'=>$r['cnt'],'cid'=>$cid];$byCur[$cid][]=$row;if($isRev)$metrics[$cid]['rev']+=max(0,$amount);else $metrics[$cid]['exp']+=max(0,$amount);$metrics[$cid]['count']+=(int)$r['cnt'];}
    foreach($metrics as $cid=>$m)$metrics[$cid]['net']=$m['rev']-$m['exp'];ob_start();?>
