function page_business_activity(){
    $year=date('Y');$from=$_GET['from']??($year.'-01-01');$to=$_GET['to']??($year.'-12-31');$selected=report_selected_currency_ids('cur');
    $services=q('SELECT id,name FROM services ORDER BY name')->fetchAll();$statuses=q('SELECT id,service_id,name FROM service_statuses ORDER BY service_id,sort_order,name')->fetchAll();$currencies=report_currency_rows();
    $activityRows=[['id'=>'أساسي','name'=>'أساسي'],['id'=>'آخر','name'=>'آخر']];$profitRows=[['id'=>'profit','name'=>'رابح'],['id'=>'loss','name'=>'خاسر'],['id'=>'zero','name'=>'صفر']];
    $svc=report_multi_values('service',$services);$st=report_multi_values('status',$statuses?:[['id'=>'0','name'=>'بدون حالة']]);$acts=report_multi_values('activity',$activityRows);$pstate=report_multi_values('pstate',$profitRows);$search=trim($_GET['q']??'');
    $rows=q("SELECT t.*,c.name customer,s.name service,COALESCE(s.activity_type,'أساسي') activity_type,ss.name status,sup.name supplier,o.name office,ag.name agent,vb.price supplier_price,vb.currency_id supplier_currency_id FROM transactions t JOIN customers c ON c.id=t.customer_id JOIN services s ON s.id=t.service_id LEFT JOIN service_statuses ss ON ss.id=t.status_id LEFT JOIN suppliers sup ON sup.id=t.supplier_id LEFT JOIN offices o ON o.id=t.office_id LEFT JOIN agents ag ON ag.id=t.agent_id LEFT JOIN visa_batches vb ON vb.id=t.visa_batch_id WHERE t.transaction_date BETWEEN ? AND ? AND t.branch_id=? AND t.currency_id IN (".implode(',',array_fill(0,count($selected),'?')).") ORDER BY t.id DESC LIMIT 2000",array_merge([$from,$to,branch_id()],$selected))->fetchAll();
    $transferCosts=[];foreach(q('SELECT transaction_id,currency_id,SUM(price) amount FROM office_transfers WHERE branch_id=? AND COALESCE(is_reversed,0)=0 GROUP BY transaction_id,currency_id',[branch_id()])->fetchAll() as $tc){$transferCosts[(int)$tc['transaction_id']][]=['currency_id'=>(int)$tc['currency_id'],'amount'=>(float)$tc['amount']];}
    $filtered=[];$tot=[];$byService=[];$bySupplier=[];$byOffice=[];$ind=['أساسي'=>0,'آخر'=>0];
    foreach($rows as $r){$cur=(int)($r['currency_id']?:2);$income=(float)$r['price'];$supplierCur=(int)($r['supplier_currency_id']?:$cur);$supplierRaw=(float)($r['supplier_price']?:0);$supplier=fx_convert($supplierRaw,$supplierCur,$cur);$office=0;foreach($transferCosts[(int)$r['id']]??[] as $oc){$office+=fx_convert((float)$oc['amount'],(int)$oc['currency_id'],$cur);} $other=0;$cost=$supplier+$office+$other;$profit=$income-$cost;$state=$profit>0.001?'profit':($profit<-0.001?'loss':'zero');$r['supplier_original']=$supplierRaw;$r['supplier_original_currency_id']=$supplierCur; if(!in_array((string)$r['service_id'],$svc,true))continue;if($r['status_id'] && !in_array((string)$r['status_id'],$st,true))continue;if(!in_array($r['activity_type']??'أساسي',$acts,true))continue;if(!in_array($state,$pstate,true))continue;if($search!=='' && mb_stripos($r['customer'].' '.$r['service'].' '.$r['status'].' '.$r['visa_number'].' '.$r['registry_number'].' '.$r['supplier'].' '.$r['office'],$search)===false)continue;$r['income_calc']=$income;$r['supplier_calc']=$supplier;$r['office_calc']=$office;$r['other_calc']=$other;$r['cost_calc']=$cost;$r['profit_calc']=$profit;$r['pstate']=$state;$filtered[]=$r;$tot[$cur]['income']=($tot[$cur]['income']??0)+$income;$tot[$cur]['supplier']=($tot[$cur]['supplier']??0)+$supplier;$tot[$cur]['office']=($tot[$cur]['office']??0)+$office;$tot[$cur]['other']=($tot[$cur]['other']??0)+$other;$tot[$cur]['cost']=($tot[$cur]['cost']??0)+$cost;$tot[$cur]['profit']=($tot[$cur]['profit']??0)+$profit;$ind[$r['activity_type']??'أساسي']+=$income;$byService[$r['service']][$cur]['income']=($byService[$r['service']][$cur]['income']??0)+$income;$byService[$r['service']][$cur]['profit']=($byService[$r['service']][$cur]['profit']??0)+$profit;$byService[$r['service']][$cur]['count']=($byService[$r['service']][$cur]['count']??0)+1;$bySupplier[$r['supplier']?:'بدون مورد'][$cur]=($bySupplier[$r['supplier']?:'بدون مورد'][$cur]??0)+$supplier;$byOffice[$r['office']?:'بدون مكتب'][$cur]=($byOffice[$r['office']?:'بدون مكتب'][$cur]??0)+$office;}
    ob_start();?>
