cur)?></td><td data-col="cost"><?=money($r['cost_calc']).' '.currency_code($cur)?></td><td data-col="profit" class="<?=$profit>=0?'profit-plus-v26':'profit-minus-v26'?>"><?=($profit>=0?'↑ ':'↓ -').money(abs($profit)).' '.currency_code($cur)?></td><td data-col="party"><?=e('المورد: '.($r['supplier']?:'—').' | المكتب: '.($r['office']?:'—').' | الوكيل: '.($r['agent']?:'—'))?></td><td data-col="visa"><?=e(($r['visa_number']?:'—').' / '.($r['registry_number']?:'—').' / '.($r['company_name']?:'—').' / '.($r['visa_type']?:'—'))?></td></tr><?php endforeach;?></tbody><tfoot><?php foreach($selected as $cid):$t=$tot[$cid]??['income'=>0,'supplier'=>0,'office'=>0,'other'=>0,'cost'=>0,'profit'=>0];?><tr class="total-row"><th colspan="6">إجمالي <?=currency_code($cid)?></th><th><?=money($t['income'])?></th><th><?=money($t['supplier'])?></th><th><?=money($t['office'])?></th><th><?=money($t['other'])?></th><th><?=money($t['cost'])?></th><th class="<?=($t['profit']??0)>=0?'profit-plus-v26':'profit-minus-v26'?>"><?=($t['profit']>=0?'↑ ':'↓ -').money(abs($t['profit']))?></th><th colspan="2"></th></tr><?php endforeach;?></tfoot></table></div></div>
