function act_delivery_save(){if(!can_edit('delivery.save')){system_no_permission('customers');return;}$id=(int)($_POST['transaction_id']??0);$t=q('SELECT t.*,c.account_id FROM transactions t JOIN customers c ON c.id=t.customer_id WHERE t.id=? AND t.branch_id=?',[$id,branch_id()])->fetch();if(!$t){flash('المعاملة غير موجودة','err');go('customers');}q('INSERT INTO delivery_receipts(transaction_id,customer_id,doc_no,receiver_name,description,created_by,created_at,branch_id) VALUES(?,?,?,?,?,?,NOW(),?)',[$id,$t['customer_id'],next_code('DEL'),$_POST['receiver_name']??'',$_POST['description']??'تسليم المعاملة',user()['id']??0,($t['branch_id']??branch_id())]);q('UPDATE transactions SET status_id=status_id WHERE id=? AND branch_id=?',[$id,branch_id()]);flash('تم تسجيل التسليم');go('delivery',['id'=>$id]);}

