function page_customer_profile(){ $id=(int)($_GET['id']??0); $c=q('SELECT c.*,p.name profession_name,ag.name agent_name FROM customers c LEFT JOIN professions p ON p.id=c.profession_id LEFT JOIN agents ag ON ag.id=c.agent_id WHERE c.id=?',[$id])->fetch(); if(!$c){flash('العميل غير موجود','err');go('customers');} if(!ensure_same_branch_v42($c['branch_id']??branch_id(),'العميل'))go('customers'); $bal=!empty($c['account_id'])?balance($c['account_id']):0; ob_start();?><div class="page-title"><h2>ملف العميل: <?=e($c['name'])?></h2><div class="actions"><a class="btn btn-outline" href="<?=route('customers')?>">رجوع</a><a class="btn btn-outline" href="<?=route('statement',['account_id'=>$c['account_id']])?>">كشف الحساب</a><a class="btn btn-red" href="<?=route('transaction_form',['customer_id'=>$c['id']])?>">إضافة خدمة</a><a class="btn btn-outline" href="<?=route('voucher_form',['type'=>'قبض','account_id'=>$c['account_id']])?>">سند قبض</a><a class="btn btn-outline" href="<?=route('voucher_form',['type'=>'صرف','account_id'=>$c['account_id']])?>">سند صرف</a><a class="btn btn-outline" href="<?=route('journal_form',['account_id'=>$c['account_id']])?>">قيد يومي</a></div></div><div class="grid grid-2"><div class="card"><h3>بيانات العميل</h3><table class="table compact-table"><tr><th>رقم العميل</th><td><?=$c['id']?></td></tr><tr><th>الاسم</th><td><?=e($c['name'])?></td></tr><tr><th>نوع الوثيقة</th><td><?=e($c['doc_type']??'جواز')?></td></tr><tr><th>رقم الوثيقة</th><td><?=e($c['passport_no'])?></td></tr><tr><th>الهاتف</th><td><?=e($c['phone'])?></td></tr><tr><th>المهنة</th><td><?=e($c['profession_name']?:$c['profession'])?></td></tr><tr><th>الوكيل</th><td><?=e($c['agent_name']?:'مباشر')?></td></tr></table></div><div class="card"><h3>الرصيد</h3><div class="stat"><div class="ico green">💼</div><div><h3><?=money($bal)?></h3><p>الرصيد يمني</p></div></div><div class="stat"><div class="ico blue">﷼</div><div><h3><?=money($bal/150)?></h3><p>تقريبي سعودي</p></div></div></div></div><br><div class="card"><h3>كل خدمات ومعاملات العميل</h3><table class="table"><tr><th>الخدمة</th><th>الحالة</th><th>السعر</th><th>الوكيل</th><th>المكتب</th><th>الشركة</th><th>المورد</th><th>رقم التأشيرة</th><th>السجل</th><th>إجراء</th></tr><?php foreach(q('SELECT t.*,c.account_id customer_account_id,s.name service,ss.name status,ag.name agent,o.name office,sup.name supplier FROM transactions t JOIN customers c ON c.id=t.customer_id JOIN services s ON s.id=t.service_id LEFT JOIN service_statuses ss ON ss.id=t.status_id LEFT JOIN agents ag ON ag.id=t.agent_id LEFT JOIN offices o ON o.id=t.office_id LEFT JOIN suppliers sup ON sup.id=t.supplier_id WHERE t.customer_id=? AND t.branch_id=? ORDER BY t.id DESC',[$id,branch_id()])->fetchAll() as $t):?><tr><td><?=e($t['service'])?></td><td><?=e($t['status']?:'بدون خدمة')?></td><td><?=money($t['price'])?></td><td><?=e($t['agent']?:'مباشر')?></td><td><?=e($t['office'])?></td><td><?=e($t['company_name'])?></td><td><?=e($t['supplier'])?></td><td><?=e($t['visa_number'])?></td><td><?=e($t['registry_number'])?></td><td><a class="btn btn-sm btn-outline" href="<?=route('transfer',['tid'=>$t['id']])?>">إرسال لمكتب</a><a class="btn btn-sm btn-outline" href="<?=route('refund',['id'=>$t['id']])?>">مردود</a><button type="button" class="btn btn-sm btn-red" onclick="openDeliveryModalV22(<?= (int)$t['id']?>,'<?=e($c['name'])?>',<?= (int)$c['id']?>,'<?=e($t['service'])?>')">تسليم</button></td></tr><?php endforeach;?></table></div><?php render('ملف العميل',ob_get_clean(),'data');}

