function act_service_update(){
    if(!can_edit('services.edit')){flash('لا تملك صلاحية التعديل','err');go('services');}
    $id=(int)$_POST['id'];$name=trim($_POST['name']??'');
    $ex=q('SELECT id FROM services WHERE name=? AND id<>? LIMIT 1',[$name,$id])->fetchColumn();
    if($ex){v13_notice('لا يمكن الحفظ','هذه الخدمة موجودة سابقاً.','services',route('service_view',['id'=>$ex]));return;}
    q('UPDATE services SET name=?,regular_price=?,individual_price=?,currency_id=?,activity_type=? WHERE id=?',[$name,$_POST['price']?:0,$_POST['price']?:0,$_POST['currency_id']?:2,(can_edit('services.activity')?($_POST['activity_type']??'أساسي'):q('SELECT activity_type FROM services WHERE id=?',[$id])->fetchColumn()),$id]);
    q('DELETE FROM service_statuses WHERE service_id=?',[$id]);
    $i=1;$seen=[];foreach(array_slice(array_filter($_POST['statuses']??[]),0,10) as $st){$st=trim($st);if($st===''||isset($seen[mb_strtolower($st)]))continue;$seen[mb_strtolower($st)]=1;q('INSERT INTO service_statuses(service_id,name,sort_order) VALUES(?,?,?)',[$id,$st,$i++]);}
    flash('تم تعديل الخدمة وحالاتها');go('service_view',['id'=>$id]);}
