function act_authorize_update(){
    if(!can_edit('visa_authorize.edit')){flash('لا تملك صلاحية التعديل','err');go('visa_status');}
    $id=(int)($_POST['id']??0);$auth=trim($_POST['auth_no']??'');$office=(int)($_POST['office_id']??0);
    if($auth===''||$office<=0){v13_notice('لا يمكن التعديل','رقم التفويض والمكتب المخلص مطلوبة.','visa_status');return;}
    $old=q('SELECT * FROM visa_authorizations WHERE id=? AND branch_id=? AND COALESCE(is_reversed,0)=0',[$id,branch_id()])->fetch();
    if(!$old){v13_notice('لا يمكن التعديل','هذا التفويض غير موجود أو تم إلغاؤه سابقاً.','visa_status');return;}
    $officeOk=q('SELECT id FROM offices WHERE id=? AND branch_id=?',[$office,branch_id()])->fetchColumn();if(!$officeOk){v13_notice('لا يمكن التعديل','المكتب المخلص غير موجود في هذا الفرع.','visa_status');return;}q('UPDATE visa_authorizations SET auth_no=?,office_id=?,notes=? WHERE id=? AND branch_id=?',[$auth,$office,$_POST['notes']??'',$id,branch_id()]);
    flash('تم تعديل بيانات التفويض');go('visa_status');}
function act_authorize_reverse(){
    if(!can_edit('visa_authorize.edit')){flash('لا تملك صلاحية التعديل','err');go('visa_status');}
    $ids=$_POST['ids']??[];if(!$ids){v13_notice('لا يمكن إلغاء التفويض','لم يتم تحديد تفويض.','visa_status');return;}
    foreach($ids as $id){
        $a=q('SELECT * FROM visa_authorizations WHERE id=? AND branch_id=? AND COALESCE(is_reversed,0)=0',[$id,branch_id()])->fetch();
        if(!$a)continue;
        q('UPDATE visa_authorizations SET is_reversed=1 WHERE id=? AND branch_id=?',[$id,branch_id()]);
        q('UPDATE visa_professions SET authorized_qty=GREATEST(authorized_qty-?,0) WHERE id=? AND branch_id=?',[(int)$a['quantity'],(int)$a['profession_id'],branch_id()]);
    }
    flash('تم إلغاء التفويض ورجعت التأشيرات إلى غير المفوضة');go('visa_status',['auth_filter'=>'not_authorized']);}
