function act_customer_update(){
    ensure_customer_page_schema_v54();
    if(!can_edit('customers.edit')){system_no_permission('customers');return;}
    $id=(int)($_POST['id']??0);$c=q('SELECT * FROM customers WHERE id=?',[$id])->fetch();if(!$c){flash('العميل غير موجود','err');go('customers');}
    if(!ensure_same_branch_v42($c['branch_id']??branch_id(),'العميل')){go('customers');}
    $name=trim($_POST['name']??'');$passport=trim($_POST['passport_no']??'');$phone=trim($_POST['phone']??'');
    $ex=q('SELECT id FROM customers WHERE branch_id=? AND (passport_no=? OR phone=?) AND id<>? LIMIT 1',[branch_id(),$passport,$phone,$id])->fetchColumn();if($ex){v13_notice('لا يمكن الحفظ','يوجد عميل آخر بنفس رقم الوثيقة أو الهاتف.','customers',route('customer_profile',['id'=>$ex]));return;}
    $profName=''; if(!empty($_POST['profession_id']))$profName=q('SELECT name FROM professions WHERE id=?',[$_POST['profession_id']])->fetchColumn()?:'';
    if(!empty($_POST['agent_id'])&&!q('SELECT id FROM agents WHERE id=? AND branch_id=?',[$_POST['agent_id'],branch_id()])->fetchColumn()){v13_notice('لا يمكن الحفظ','الوكيل المحدد غير تابع لهذا الفرع.','customers');return;}
    $source=!empty($_POST['agent_id'])?'وكيل':'مباشر';
    q('UPDATE customers SET name=?,doc_type=?,passport_no=?,phone=?,profession=?,profession_id=?,agent_id=?,customer_source=?,notes=? WHERE id=? AND branch_id=?',[$name,$_POST['doc_type']??'جواز',$passport,$phone,$profName,$_POST['profession_id']?:null,$_POST['agent_id']?:null,$source,$_POST['notes']??'',$id,branch_id()]);
    if($c['account_id'])q('UPDATE accounts SET name=? WHERE id=?',[$name,$c['account_id']]);
    flash('تم تعديل العميل');go('customer_profile',['id'=>$id]);}
