function act_account_save(){$parent=$_POST['parent_id']?:null;if($parent){$pa=q('SELECT branch_id,type FROM accounts WHERE id=?',[$parent])->fetch();if(!$pa){flash('الحساب الأب غير موجود','err');go('accounts');}if(($pa['type']??'')!=='عام' && (int)($pa['branch_id']??0)!==(int)branch_id()){flash('لا يمكن إنشاء حساب تحت حساب تابع لفرع آخر','err');go('accounts');}}$name=trim($_POST['name']??'');if($name===''){flash('اسم الحساب مطلوب','err');go('accounts');}$existsName=q('SELECT id FROM accounts WHERE name=? AND type=? AND branch_id=? LIMIT 1',[$name,$_POST['type']??'عام',branch_id()])->fetchColumn();if($existsName){flash('يوجد حساب بنفس الاسم والتصنيف داخل هذا الفرع','err');go('accounts',['selected'=>$existsName]);}$no=trim($_POST['account_no']??'');if($no===''){$prefix=$parent?(q('SELECT account_no FROM accounts WHERE id=?',[$parent])->fetchColumn()?:''):'9';$last=(int)q('SELECT COUNT(*) FROM accounts WHERE parent_id '.($parent?'=?':'IS NULL'),$parent?[$parent]:[])->fetchColumn();do{$no=$prefix.(++$last);$dup=q('SELECT id FROM accounts WHERE account_no=? LIMIT 1',[$no])->fetchColumn();}while($dup);}else{if(q('SELECT id FROM accounts WHERE account_no=? LIMIT 1',[$no])->fetchColumn()){flash('رقم الحساب مستخدم سابقاً','err');go('accounts');}}q('INSERT INTO accounts(account_no,name,type,nature,currency_id,parent_id,created_at,branch_id) VALUES(?,?,?,?,?,?,NOW(),?)',[$no,$name,$_POST['type'],$_POST['nature'],1,$parent,branch_id()]);flash('تم حفظ الحساب');go('accounts');}



function has_column_v39($table,$col){
    try{$table=preg_replace('/[^A-Za-z0-9_]/','',(string)$table);$col=preg_replace('/[^A-Za-z0-9_]/','',(string)$col);return (bool)q("SHOW COLUMNS FROM `$table` LIKE '$col'")->fetch();}catch(Throwable $e){return false;}
}

