k',['branch_id'=>$b['id']])?>">مخزون الفرع</a></div><?php endif;?></div></div><?php render('إدارة الفروع',ob_get_clean(),'branches');}
function act_branch_save(){verify(); if(!can_branch_manage_v41()){system_no_permission('branches');return;} $name=trim($_POST['name']??''); if($name===''){flash('اسم الفرع مطلوب','err');go('branches');}$code='BR'.str_pad((string)((int)q('SELECT COUNT(*) FROM branches')->fetchColumn()+1),3,'0',STR_PAD_LEFT).date('His'); q('INSERT INTO branches(name,code,city,address,phone,manager_employee_id,is_main,is_active,created_by,created_at) VALUES(?,?,?,?,?,?,0,1,?,NOW())',[$name,$code,$_POST['city']??'',$_POST['address']??'',$_POST['phone']??'',$_POST['manager_employee_id']?:null,user()['id']??0]);$id=(int)db()->lastInsertId();ensure_branch_accounts_v41($id);$managerId=(int)($_POST['manager_employee_id']??0); if($managerId){q('UPDATE employees SET branch_id=? WHERE id=?',[$id,$managerId]);$existingUid=user_id_for_employee_v39($managerId);if($existingUid){q('UPDATE users SET default_branch_id=?,current_branch_id=? WHERE id=?',[$id,$id,$existingUid]);} $emp=q('SELECT * FROM employees WHERE id=?',[$managerId])->fetch(); if($emp && !user_id_for_employee_v39($managerId)){ $base=trim($_POST['branch_username']??''); if($base==='')$base='branch_'.$id; $username=$base;$n=1; while(q('SELECT id FROM users WHERE username=? LIMIT 1',[$username])->fetchColumn()){$username=$base.'_'.$n++;} $plain=$_POST['branch_password']??''; if($plain!=='' && strlen($plain)<8){flash('كلمة مرور مدير الفرع يجب أن تكون 8 أحرف على الأقل','err');go('branches',['id'=>$id]);} if($plain==='')$plain='Branch@'.$id.date('His'); q('INSERT INTO users(employee_id,full_name,username,password_hash,role_id,is_active,default_branch_id,current_branch_id,created_at) VALUES(?,?,?,?,2,1,?,?,NOW())',[$managerId,$emp['name'],$username,password_hash($plain,PASSWORD_DEFAULT),$id,$id]);$uid=(int)db()->lastInsertId();link_user_employee_v39($uid,$managerId);foreach(['system.login','dashboard.view','customers.view','customers.create','customers.profile','transactions.view','transactions.create','voucher.view','voucher.create','journal.view','notifications.view','drafts.view'] as $perm)q('INSERT IGNORE INTO user_permissions(user_id,permission_key,granted,created_at) VALUES(?,?,1,NOW())',[$uid,$perm]); flash('تم إنشاء الفرع وحساب مدير الفرع. اسم المستخدم: '.$username.' | كلمة المرور: '.$plain); } else flash('تم إنشاء الفرع وربطه، ولم يتم إنشاء مستخدم لأن المدير لديه حساب سابق أو غير موجود.'); } else flash('تم إنشاء الفرع وربط حساباته تلقائياً');activity_log('branch.create','إنشاء فرع','الفروع','branch',$id,$name,'تم إنشاء الفرع مع حساباته التلقائية');go('branches',['id'=>$id]);}
function act_branch_switch(){verify();if(!can_branch_manage_v41()){system_no_permission('branches');return;}$id=(int)($_POST['branch_id']??1);$b=q('SELECT * FROM branches WHERE id=? AND is_active=1',[$id])->fetch();if(!$b){flash('الفرع غير موجود أو موقوف','err');go('dashboard');}$_SESSION['current_branch_id']=$id;try{q('UPDATE users SET current_branch_id=? WHERE id=?',[$id,user()['id']??0]);$_SESSION['user']['current_branch_id']=$id;}catch(Throwable $e){}activity_log('branch.switch','فتح فرع','الفروع','branch',$id,$b['name'],'تم فتح الفرع الحالي');flash('أنت الآن تعمل داخل '.$b['name']);go('dashboard');}
function act_branch_permissions_save(){verify();if(!can_branch_manage_v41()){system_no_permission('branches');return;}$bid=(int)($_POST['branch_id']??0);q('DELETE FROM branch_permissions WHERE branch_id=?',[$bid]);foreach($_POST['perm']??[] as $p)q('INSERT INTO branch_permissions(branch_id,permission_key,granted,created_at) VALUES(?,?,1,NOW())',[$bid,$p]);flash('تم حفظ صلاحيات الفرع');go('branches',['id'=>$bid]);}

function ensure_user_employee_schema_v39(){
    try{q("CREATE TABLE IF NOT EXISTS user_employee_links(user_id INT NOT NULL PRIMARY KEY, employee_id INT NOT NULL, created_at DATETIME, INDEX(employee_id))");}catch(Throwable $e){}
    try{ensure_column_exists('users','employee_id','INT NULL');}catch(Throwable $e){}
    return has_column_v39('users','employee_id');
}
function users_employee_column_ready_v39(){static $ok=null;if($ok===null)$ok=ensure_user_employee_schema_v39();return $ok;}
function get_user_employee_id_v39($uid){
    $uid=(int)$uid;if(!$uid)return 0;users_employee_column_ready_v39();
    if(has_column_v39('users','employee_id')){try{return (int)q('SELECT employee_id FROM users WHERE id=?',[$uid])->fetchColumn();}catch(Throwable $e){}}
    try{return (int)q('SELECT employee_id FROM user_employee_links WHERE user_id=?',[$uid])->fetchColumn();}catch(Throwable $e){return 0;}
}
function link_user_employee_v39($uid,$employeeId){
    $uid=(int)$uid;$employeeId=(int)$employeeId;if(!$uid||!$employeeId)return;
    users_employee_column_ready_v39();
    if(has_column_v39('users','employee_id')){try{q('UPDATE users SET employee_id=? WHERE id=?',[$employeeId,$uid]);return;}catch(Throwable $e){}}
    try{q('INSERT INTO user_employee_links(user_id,employee_id,created_at) VALUES(?,?,NOW()) ON DUPLICATE KEY UPDATE employee_id=VALUES(employee_id)',[$uid,$employeeId]);}catch(Throwable $e){}
}
function user_id_for_employee_v39($employeeId){
    $employeeId=(int)$employeeId;if(!$employeeId)return 0;users_employee_column_ready_v39();
    if(has_column_v39('users','employee_id')){try{return (int)q('SELECT id FROM users WHERE employee_id=? LIMIT 1',[$employeeId])->fetchColumn();}catch(Throwable $e){}}
    try{return (int)q('SELECT user_id FROM user_employee_links WHERE employee_id=? LIMIT 1',[$employeeId])->fetchColumn();}catch(Throwable $e){return 0;}
}
function all_user_employee_links_v39(){
    users_employee_column_ready_v39();$m=[];
    if(has_column_v39('users','employee_id')){try{foreach(q('SELECT id,employee_id FROM users')->fetchAll() as $r){if(!empty($r['employee_id']))$m[(int)$r['id']]=(int)$r['employee_id'];}}catch(Throwable $e){}}
    try{foreach(q('SELECT user_id,employee_id FROM user_employee_links')->fetchAll() as $r){if(!isset($m[(int)$r['user_id']]))$m[(int)$r['user_id']]=(int)$r['employee_id'];}}catch(Throwable $e){}
    return $m;
}

function ensure_employee_user_link_v36(){
    ensure_user_employee_schema_v39();
    try{
        $admin=q("SELECT * FROM users WHERE role_id=1 ORDER BY id ASC LIMIT 1")->fetch();
        if($admin && !get_user_employee_id_v39($admin['id'])){
            $emp=q("SELECT * FROM employees WHERE name LIKE ? ORDER BY id ASC LIMIT 1",['%محمد الحاج%'])->fetch();
            if(!$emp){
                $aid=add_account('موظف','أ. محمد الحاج','debit',1);
                q("INSERT INTO employees(name,phone,job_title,salary,account_id,created_at) VALUES(?,?,?,?,?,NOW())",['أ. محمد الحاج','','مدير النظام',0,$aid]);
                $emp=q('SELECT * FROM employees WHERE id=?',[db()->lastInsertId()])->fetch();
            }
            link_user_employee_v39($admin['id'],$emp['id']);
            q('UPDATE users SET full_name=? WHERE id=?',[$emp['name'],$admin['id']]);
        }
    }catch(Throwable $e){try{activity_log('schema.link','فشل ربط المدير بالموظف','النظام','','','',$e->getMessage(),'فشل','خطر');}catch(Throwable $x){}}
}

function employee_user_rows_v36(){
    ensure_employee_user_link_v36();
    $employees=[];foreach(q('SELECT * FROM employees ORDER BY name,id')->fetchAll() as $e){$e['user_id']=0;$e['username']='';$e['full_name']='';$e['role_id']=null;$e['user_active']=null;$e['last_login_at']='';$employees[(int)$e['id']]=$e;}
    $links=all_user_employee_links_v39();$usedUsers=[];
    foreach(q('SELECT id,username,full_name,role_id,is_active,last_login_at FROM users ORDER BY full_name,username')->fetchAll() as $u){
        $eid=$links[(int)$u['id']]??0;
        if($eid && isset($employees[$eid])){$employees[$eid]['user_id']=$u['id'];$employees[$eid]['username']=$u['username'];$employees[$eid]['full_name']=$u['full_name'];$employees[$eid]['role_id']=$u['role_id'];$employees[$eid]['user_active']=$u['is_active'];$employees[$eid]['last_login_at']=$u['last_login_at'];$usedUsers[(int)$u['id']]=1;}
    }
    $rows=array_values($employees);
    foreach(q('SELECT id,username,full_name,role_id,is_active,last_login_at FROM users ORDER BY full_name,username')->fetchAll() as $u){if(empty($usedUsers[(int)$u['id']]))$rows[]=['id'=>0,'employee_id'=>0,'name'=>'مستخدم غير مربوط بموظف','job_title'=>'','phone'=>'','user_id'=>$u['id'],'username'=>$u['username'],'full_name'=>$u['full_name'],'role_id'=>$u['role_id'],'user_active'=>$u['is_active'],'last_login_at'=>$u['last_login_at']];}
    return $rows;
}

function user_for_employee_v36($employeeId,$userId=0){
    ensure_employee_user_link_v36();
    if($userId){$u=q('SELECT * FROM users WHERE id=?',[$userId])->fetch();if(!$u)return null;$eid=get_user_employee_id_v39($userId);$e=$eid?q('SELECT * FROM employees WHERE id=?',[$eid])->fetch():null;if($e){$u['employee_name']=$e['name'];$u['employee_id_real']=$e['id'];$u['job_title']=$e['job_title'];}return $u;}
    if($employeeId){$uid=user_id_for_employee_v39($employeeId);if($uid)return user_for_employee_v36(0,$uid);$e=q('SELECT * FROM employees WHERE id=?',[$employeeId])->fetch();return $e?['employee_name'=>$e['name'],'employee_id_real'=>$e['id'],'job_title'=>$e['job_title']]:null;}
    return null;
}

function permission_allowed_to_grant_v36($perm){
    $me=user(); if((int)($me['role_id']??0)===1)return true;
    return can_edit($perm);
}

function page_users(){
    ensure_employee_user_link_v36();
    if(!can_edit('permissions.manage') && (int)(user()['role_id']??0)!==1){system_no_permission('dashboard');return;}
    $employeeId=(int)($_GET['employee_id']??0);$userId=(int)($_GET['user_id']??0);
    if(!$employeeId && !$userId){$cur=user(); $linked=get_user_employee_id_v39((int)($cur['id']??0)); if($linked)$employeeId=$linked; else $userId=(int)($cur['id']??1);}
    $rows=employee_user_rows_v36();
    $selectedRow=null;foreach($rows as $r){if(($employeeId && (int)$r['id']===$employeeId)||($userId && (int)$r['user_id']===$userId)){$selectedRow=$r;break;}}
    if(!$selectedRow && $rows){$selectedRow=$rows[0];$employeeId=(int)$selectedRow['id'];$userId=(int)($selectedRow['user_id']??0);}    
    $selUser=!empty($selectedRow['user_id'])?q('SELECT * FROM users WHERE id=?',[$selectedRow['user_id']])->fetch():null;
    $currentPerms=[]; if($selUser){foreach(q('SELECT permission_key FROM user_permissions WHERE user_id=? AND granted=1',[$selUser['id']])->fetchAll() as $p)$currentPerms[$p['permission_key']]=1; if((int)($selUser['role_id']??0)===1){foreach(permission_tree_v35() as $items){foreach($items as $k=>$v)$currentPerms[$k]=1;}}}
    $tree=permission_tree_v35(); ob_start();?>
