function act_user_save(){verify();if(!can_edit('permissions.manage')){activity_log('permission.denied','محاولة إنشاء مستخدم بدون صلاحية','الإدارة','users','','','رفض إنشاء مستخدم','فشل','مهم');system_no_permission('users');return;} $employeeId=(int)($_POST['employee_id']??0);$username=trim($_POST['username']??'');$pass=$_POST['password']??'';$confirm=$_POST['password_confirm']??'';$miss=[];if(!$employeeId)$miss[]='الموظف';if($username==='')$miss[]='اسم المستخدم';if($pass==='')$miss[]='كلمة المرور';if($confirm==='')$miss[]='تأكيد كلمة المرور';if($miss){v13_notice('لا يمكن إنشاء المستخدم','يرجى تعبئة: '.implode('، ',$miss),'users',['employee_id'=>$employeeId]);return;} if(strlen($pass)<8){v13_notice('لا يمكن إنشاء المستخدم','كلمة المرور يجب أن تكون 8 أحرف على الأقل.','users',['employee_id'=>$employeeId]);return;} if($pass!==$confirm){v13_notice('لا يمكن إنشاء المستخدم','كلمة المرور وتأكيدها غير متطابقين.','users',['employee_id'=>$employeeId]);return;} $emp=q('SELECT * FROM employees WHERE id=? AND branch_id=?',[$employeeId,branch_id()])->fetch();if(!$emp){v13_notice('لا يمكن إنشاء المستخدم','الموظف غير موجود.','users');return;} $exists=q('SELECT id FROM users WHERE username=? LIMIT 1',[$username])->fetchColumn();if($exists){v13_notice('لا يمكن إنشاء المستخدم','اسم المستخدم مستخدم سابقاً.','users',['employee_id'=>$employeeId]);return;} $has=user_id_for_employee_v39($employeeId);if($has){v13_notice('لا يمكن إنشاء المستخدم','هذا الموظف لديه حساب مستخدم سابقاً.','users',['employee_id'=>$employeeId]);return;} $hash=password_hash($pass,PASSWORD_DEFAULT);if(has_column_v39('users','employee_id')){q('INSERT INTO users(employee_id,full_name,username,password_hash,role_id,is_active,default_branch_id,current_branch_id,created_at) VALUES(?,?,?,?,2,1,?,?,NOW())',[$employeeId,$emp['name'],$username,$hash,(int)($emp['branch_id']??branch_id()),(int)($emp['branch_id']??branch_id())]);}else{q('INSERT INTO users(full_name,username,password_hash,role_id,is_active,default_branch_id,current_branch_id,created_at) VALUES(?,?,?,2,1,?,?,NOW())',[$emp['name'],$username,$hash,(int)($emp['branch_id']??branch_id()),(int)($emp['branch_id']??branch_id())]);}$uid=(int)db()->lastInsertId();link_user_employee_v39($uid,$employeeId);foreach(basic_permissions_v35() as $p)q('INSERT IGNORE INTO user_permissions(user_id,permission_key,granted,created_at) VALUES(?,?,1,NOW())',[$uid,$p]);activity_log('user.create','إنشاء مستخدم لموظف','الإدارة','user',$uid,$emp['name'],'تم إنشاء الحساب للموظف بصلاحيات أساسية');flash('تم إنشاء المستخدم وربطه بالموظف بالصلاحيات الأساسية فقط');go('users',['employee_id'=>$employeeId]);}
