function act_notification_save(){verify();if(!can_edit('notifications.manage')){system_no_permission('notifications');return;} $title=trim($_POST['title']??'');$body=trim($_POST['body']??'');if($title===''||$body===''){flash('عنوان الإشعار ومضمونه مطلوبان','err');go('notifications');}$show=!empty($_POST['show_at'])?str_replace('T',' ',$_POST['show_at']).':00':null;$requires=isset($_POST['requires_ack'])?1:0;$allowedSeverity=['info','success','warning','error','security'];$severity=in_array($_POST['severity']??'info',$allowedSeverity,true)?$_POST['severity']:'info';$allowedPos=['top-right','top-left','bottom-right','bottom-left'];$pos=in_array($_POST['position']??'top-right',$allowedPos,true)?$_POST['position']:'top-right';$targets=[];if(!empty($_POST['all_users'])){$targets=array_map('intval',array_column(q('SELECT id FROM users WHERE is_active=1')->fetchAll(),'id'));}else{$targets=array_values(array_filter(array_map('intval',$_POST['user_ids']??[])));} if(!$targets)$targets=[null];foreach($targets as $uid){q('INSERT INTO notifications(user_id,notification_type,title,body,severity,show_at,repeat_rule,created_by,created_at,requires_ack,delivery_status,position,color_scheme,target_branch_id) VALUES(?,?,?,?,?,?,?,?,NOW(),?,?,?,?,?)',[$uid,'user',$title,$body,$severity,$show,'once',user()['id']??0,$requires,'لم يصله',$pos,$severity,branch_id()]);}activity_log('notification.create','إنشاء إشعار مستخدم','الإشعارات','notification','','',$title.' / عدد المستلمين: '.count($targets));flash('تم حفظ الإشعار وإرساله للمستخدمين');go('notifications',['tab'=>'user']);}
