function act_financial_period_save_v53(){
    verify();if(!can_manage_financial_periods_v53()){system_no_permission('financial_periods');return;}accounting_schema_v53();
    $year=(int)($_POST['fiscal_year']??date('Y'));$start=$_POST['start_date']?:($year.'-01-01');$end=$_POST['end_date']?:($year.'-12-31');
    if($year<2000||$year>2100||$start>$end){flash('بيانات السنة المالية غير صحيحة','err');go('financial_periods');}
    $existing=q('SELECT status FROM financial_periods WHERE branch_id=? AND fiscal_year=?',[branch_id(),$year])->fetchColumn();
    if($existing==='closed'){flash('لا يمكن تعديل سنة مالية مقفلة قبل إعادة فتحها','err');go('financial_periods');}
    q('INSERT INTO financial_periods(branch_id,fiscal_year,start_date,end_date,status,created_by,created_at) VALUES(?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE start_date=VALUES(start_date),end_date=VALUES(end_date)',[branch_id(),$year,$start,$end,'open',user()['id']??0]);
    activity_log('period.save','حفظ سنة مالية','الإقفال المالي','financial_period',$year,(string)$year,'الفترة: '.$start.' إلى '.$end,'ناجح','حساس');flash('تم حفظ السنة المالية');go('financial_periods');
}
function act_financial_period_close_v53(){
    verify();if(!can_manage_financial_periods_v53()){system_no_permission('financial_periods');return;}$id=(int)($_POST['id']??0);$p=q('SELECT * FROM financial_periods WHERE id=? AND branch_id=?',[$id,branch_id()])->fetch();if(!$p){flash('الفترة غير موجودة','err');go('financial_periods');}
    $diffs=period_balance_diffs_v53($p['start_date'],$p['end_date'],branch_id());foreach($diffs as $d){if(abs($d['diff'])>0.01){flash('لا يمكن إقفال الفترة: ميزان الحركة غير متوازن في عملة '.$d['code'].' بفارق '.money($d['diff']),'err');go('financial_periods');}}
    q("UPDATE financial_periods SET status='closed',closed_by=?,closed_at=NOW(),closing_note=? WHERE id=? AND branch_id=?",[(int)(user()['id']??0),$_POST['closing_note']??'',$id,branch_id()]);
    activity_log('period.close','إقفال فترة مالية','الإقفال المالي','financial_period',$id,$p['fiscal_year'],'تم إقفال الفترة '.$p['start_date'].' إلى '.$p['end_date'],'ناجح','حساس');flash('تم إقفال الفترة المالية، وأصبحت الحركات داخلها ممنوعة حتى إعادة فتحها');go('financial_periods');
}
function act_financial_period_reopen_v53(){
    verify();if(!can_manage_financial_periods_v53()){system_no_permission('financial_periods');return;}$id=(int)($_POST['id']??0);$p=q('SELECT * FROM financial_periods WHERE id=? AND branch_id=?',[$id,branch_id()])->fetch();if(!$p){flash('الفترة غير موجودة','err');go('financial_periods');}
    q("UPDATE financial_periods SET status='open',reopened_by=?,reopened_at=NOW() WHERE id=? AND branch_id=?",[(int)(user()['id']??0),$id,branch_id()]);
    activity_log('period.reopen','إعادة فتح فترة مالية','الإقفال المالي','financial_period',$id,$p['fiscal_year'],'تمت إعادة فتح الفترة','ناجح','حساس');flash('تمت إعادة فتح الفترة المالية');go('financial_periods');
}
function act_backup_create_v53(){
    verify();if(!can_create_backup_v53()){system_no_permission('financial_periods');return;}try{$b=create_database_backup_v53($_POST['notes']??'');flash('تم إنشاء النسخة الاحتياطية: '.$b['file'].' بحجم '.money($b['size']/1024).' KB');}catch(Throwable $e){flash('تعذر إنشاء النسخة: '.$e->getMessage(),'err');}go('financial_periods');
}
function act_backup_download_v53(){
    if(!can_create_backup_v53()){system_no_permission('financial_periods');return;}$id=(int)($_GET['id']??0);$b=q('SELECT * FROM accounting_backups WHERE id=?',[$id])->fetch();if(!$b){flash('النسخة غير موجودة','err');go('financial_periods');}
    $base=realpath(backup_dir_v53());$path=realpath($b['file_path']);if(!$base||!$path||strpos($path,$base)!==0||!is_file($path)){flash('ملف النسخة غير موجود على القرص','err');go('financial_periods');}
    activity_log('backup.download','تنزيل نسخة احتياطية','الإدارة','backup',$id,$b['file_name'],'تنزيل ملف نسخة احتياطية','ناجح','حساس');
    header('Content-Type: application/sql');header('Content-Length: '.filesize($path));header('Content-Disposition: attachment; filename="'.basename($path).'"');readfile($path);exit;
}
function readiness_badge_v55($ok){return $ok?'<span class="badge green">جاهز</span>':'<span class="badge red">يحتاج معالجة</span>';}
function readiness_audit_v55(){
    $branchId=branch_id();$items=[];$add=function($key,$title,$ok,$detail,$action='') use (&$items){$items[]=['key'=>$key,'title'=>$title,'ok'=>(bool)$ok,'detail'=>$detail,'action'=>$action];};
    $companyOk=trim(company_display_name_v55())!==''&&trim(setting('company_phone',cfg('company_phone')))!==''&&trim(setting('company_address',cfg('company_address')))!=='';
    $add('company','بيانات المنشأة',$companyOk,'اسم المنشأة والهاتف والعنوان مطلوبة قبل تسليم نسخة لعميل.',route('company_settings',['tab'=>'company']));
    $tenant=current_tenant_v56(true);
    $add('tenant_database','عزل قاعدة بيانات المنشأة',!empty($tenant['db_name']),'المنشأة الحالية: '.($tenant['tenant_name']??'غير محددة').' | قاعدة البيانات: '.($tenant['db_name']??'غير محددة'),route('tenants'));
    $lic=license_state_v45();$add('license','الترخيص',!$lic['locked']&&!$lic['expired'],'الحالة: '.$lic['status'].' | النوع: '.$lic['type'].' | النهاية: '.($lic['end']?:'غير محدد'),route('company_settings',['tab'=>'license']));
    $backup=q('SELECT COUNT(*) c,MAX(created_at) last_at FROM accounting_backups WHERE branch_id=? OR branch_id IS NULL',[$branchId])->fetch()?:['c'=>0,'last_at'=>''];
    $add('backup','النسخ الاحتياطي',(int)($backup['c']??0)>0,'آخر نسخة: '.(($backup['last_at']??'')?:'لا توجد نسخة احتياطية بعد'),route('financial_periods'));
    $ledger=q("SELECT l.currency_id,COALESCE(SUM(l.debit),0) debit,COALESCE(SUM(l.credit),0) credit FROM ledger_entries l WHERE l.branch_id=? GROUP BY l.currency_id",[$branchId])->fetchAll();
    $ledgerOk=true;$ledgerDetail=[];foreach($ledger as $r){$diff=round((float)$r['debit']-(float)$r['credit'],2);if(abs($diff)>0.01)$ledgerOk=false;$ledgerDetail[]=currency_code($r['currency_id']).' فرق '.money($diff);}
    $add('ledger','توازن دفتر الأستاذ',$ledgerOk,$ledgerDetail?implode(' | ',$ledgerDetail):'لا توجد حركات دفترية بعد.',route('trial_balance'));
    $sourceDiffs=q("SELECT l.source_type,l.source_id,l.currency_id,ROUND(SUM(l.debit-l.credit),2) diff,COUNT(*) line_count FROM ledger_entries l WHERE l.branch_id=? GROUP BY l.source_type,l.source_id,l.currency_id HAVING ABS(diff)>0.01 ORDER BY l.source_type,l.source_id,l.currency_id LIMIT 20",[$branchId])->fetchAll();
    $add('source_balance','توازن كل سند/قيد حسب العملة',count($sourceDiffs)===0,count($sourceDiffs)?'يوجد '.count($sourceDiffs).' مصدر غير متوازن ضمن أول 20 نتيجة.':'كل المصادر المتاحة متوازنة حسب العملة.',route('statement'));
    $missingCost=(int)q("SELECT COUNT(*) FROM transactions WHERE branch_id=? AND visa_batch_id IS NOT NULL AND (supplier_journal_id IS NULL OR supplier_journal_id=0)",[$branchId])->fetchColumn();
    $add('visa_cost','تكلفة التأشيرات المباعة',$missingCost===0,$missingCost?'يوجد '.$missingCost.' معاملة بتأشيرة بدون قيد تكلفة.':'كل معاملات التأشيرات المرحلة لها قيد تكلفة.',route('business_activity'));
    $dupV=(int)q("SELECT COUNT(*) FROM (SELECT voucher_no FROM vouchers WHERE branch_id=? AND voucher_no<>'' GROUP BY voucher_no HAVING COUNT(*)>1) x",[$branchId])->fetchColumn();
    $dupJ=(int)q("SELECT COUNT(*) FROM (SELECT entry_no FROM journal_entries WHERE branch_id=? AND entry_no<>'' GROUP BY entry_no HAVING COUNT(*)>1) x",[$branchId])->fetchColumn();
    $add('doc_numbers','تكرار أرقام السندات والقيود',$dupV===0&&$dupJ===0,'سندات مكررة: '.$dupV.' | قيود مكررة: '.$dupJ,route('statement'));
    $admin=q("SELECT password_hash FROM users WHERE username='admin' LIMIT 1")->fetchColumn();
    $defaultPass=$admin?password_verify('Admin@12345',$admin):false;
    $add('admin_password','كلمة مرور مدير النظام',!$defaultPass,$defaultPass?'كلمة مرور admin ما زالت افتراضية ويجب تغييرها قبل البيع.':'كلمة مرور admin ليست الافتراضية المعروفة.',route('users'));
    $ready=count(array_filter($items,fn($i)=>!$i['ok']))===0;
    return ['ready'=>$ready,'items'=>$items,'ledger'=>$ledger,'source_diffs'=>$sourceDiffs,'missing_cost'=>$missingCost,'backup'=>$backup];
}
