function tenant_admin_allowed_v56(){return (int)(user()['role_id']??0)===1 || can_edit('settings.system');}
function tenant_db_name_for_code_v56($code){global $config;$code=tenant_clean_code_v56($code);$prefix=$config['tenancy']['db_prefix']??'ababilsoft_tenant_';return preg_replace('/[^A-Za-z0-9_]/','',$prefix.$code);}
function tenant_install_sql_statements_v56(){
    $file=__DIR__.'/database/install.sql';
    if(!is_file($file))throw new RuntimeException('ملف التثبيت database/install.sql غير موجود.');
    $sql=file_get_contents($file);
    $sql=preg_replace('/^\s*CREATE\s+DATABASE\b.*?;\s*$/mi','',$sql);
    $sql=preg_replace('/^\s*USE\s+`?[^`;]+`?\s*;\s*$/mi','',$sql);
    $parts=preg_split('/;\s*(?:\r?\n|$)/',$sql);
    return array_values(array_filter(array_map('trim',$parts),fn($s)=>$s!==''));
}
function tenant_install_database_v56($dbName,$tenantName,$adminUser,$adminPass){
    $server=pdo_for_database_v56(null);
    $server->exec('CREATE DATABASE IF NOT EXISTS '.mysql_identifier_v56($dbName).' CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci');
    $pdo=pdo_for_database_v56($dbName);
    $pdo->exec('SET NAMES utf8mb4');
    foreach(tenant_install_sql_statements_v56() as $stmt){
        try{$pdo->exec($stmt.';');}
        catch(Throwable $e){throw new RuntimeException('تعذر تجهيز قاعدة المنشأة عند الأمر: '.substr($stmt,0,140).' | '.$e->getMessage());}
    }
    $hash=password_hash($adminPass,PASSWORD_DEFAULT);
    $settings=[
        'establishment_name'=>$tenantName,
        'company_name'=>$tenantName,
        'company_subtitle'=>'إدارة متكاملة لمكاتب السفريات والسياحة',
        'license_status'=>'trial',
        'license_start'=>date('Y-m-d H:i:s')
    ];
    $set=$pdo->prepare('INSERT INTO system_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');
    foreach($settings as $k=>$v)$set->execute([$k,$v]);
    $u=$pdo->prepare('UPDATE users SET full_name=?,username=?,password_hash=?,role_id=1,is_active=1 WHERE id=1');
    $u->execute(['مدير '.$tenantName,$adminUser,$hash]);
}
