function act_tenant_save_v56(){
    verify();if(!tenant_admin_allowed_v56()){system_no_permission('settings');return;}
    $name=trim($_POST['tenant_name']??'');$rawCode=trim($_POST['tenant_code']??'');
    $code=strtolower($rawCode);$code=preg_replace('/[^a-z0-9_]+/','_',$code);$code=trim($code,'_');
    if($name===''){flash('اسم المنشأة مطلوب','err');go('tenants');}
    if($code==='')$code='tenant_'.date('YmdHis');
    if(tenant_by_code_v56($code)){flash('كود المنشأة مستخدم سابقاً','err');go('tenants');}
    $adminUser=trim($_POST['admin_username']??'admin');$pass=$_POST['admin_password']??'';$confirm=$_POST['admin_password_confirm']??'';
    if($adminUser==='')$adminUser='admin';
    if(strlen($pass)<8){flash('كلمة مرور مدير المنشأة يجب أن تكون 8 أحرف على الأقل','err');go('tenants');}
    if($pass!==$confirm){flash('تأكيد كلمة المرور غير مطابق','err');go('tenants');}
    $dbName=tenant_db_name_for_code_v56($code);
    try{
        tenant_install_database_v56($dbName,$name,$adminUser,$pass);
        central_q_v56('INSERT INTO tenants(tenant_code,tenant_name,db_name,db_host,db_port,db_user,db_pass,db_charset,status,is_default,created_by,created_at) VALUES(?,?,?,?,?,?,?,?,?,0,?,NOW())',[$code,$name,$dbName,cfg('db')['host']??'127.0.0.1',cfg('db')['port']??'3306',cfg('db')['user']??'root',cfg('db')['pass']??'',cfg('db')['charset']??'utf8mb4','active',user()['id']??0]);
        activity_log('tenant.create','إنشاء منشأة مستقلة','الإدارة','tenant',$code,$name,'قاعدة البيانات: '.$dbName,'ناجح','حساس');
        flash('تم إنشاء منشأة مستقلة بقاعدة بيانات: '.$dbName.' | المستخدم: '.$adminUser);
    }catch(Throwable $e){flash('تعذر إنشاء المنشأة: '.$e->getMessage(),'err');}
    go('tenants');
}
