<?php if($tab==='license'):?><div class="card"><h3>إعدادات الترخيص المحلي</h3><div class="license-panel"><p>الحالة: <?=license_status_badge_v45()?> | النوع: <?=e($lic['type'])?> | النهاية: <?=e($lic['end']?:'غير محدد')?> | المحاولات الخاطئة: <?=e($lic['attempts'])?></p><?php if($lic['locked']):?><div class="flash error">شاشة الترخيص مقفلة: <?=e($lic['reason']?:'محاولات خاطئة كثيرة')?>. لا تفتح إلا ببيانات الشركة الصحيحة.</div><?php endif;?><form method="post" action="<?=route('license_activate')?>"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><div class="field"><label>اسم مستخدم الشركة</label><input name="company_user" required></div><div class="field"><label>كلمة مرور الشركة</label><input type="password" name="company_pass" required></div><div class="field"><label>نوع الترخيص</label><select name="license_type" onchange="document.getElementById('licenseQty').style.display=this.value==='yearly'?'none':'block'"><option value="daily">يومي</option><option value="weekly">أسبوعي</option><option value="monthly">شهري</option><option value="yearly">سنوي إلى نهاية السنة الحالية</option></select></div><div class="field" id="licenseQty"><label>عدد المدة</label><input type="number" name="qty" min="1" value="1"></div></div><label class="mini-check"><input type="checkbox" name="branches_enabled" <?=setting_bool('branches_enabled',true)?'checked':''?>> منح صلاحية الفروع وربطها محاسبياً</label><br><button class="btn btn-red">تفعيل / تغيير الترخيص</button></form></div></div><?php endif;?><?php render('إعدادات المنشأة والسندات',ob_get_clean(),'settings');}
function act_settings_save(){
    verify();
    if(!can_edit('settings.system') && (int)(user()['role_id']??0)!==1){system_no_permission('settings');return;}
    $sec=$_POST['section']??'';
    $tab='company';
    if(in_array($sec,['company','office'],true)){
        foreach(['establishment_name','company_name','company_subtitle','company_phone','company_address','company_email','company_website','commercial_register','tax_number'] as $k)set_setting($k,$_POST[$k]??'');
        $tab='company';
    }elseif($sec==='vouchers'){
        foreach(['voucher_red_note','receipt_label','payment_label','voucher_receipt_title','voucher_payment_title','voucher_default_payment_method','voucher_default_currency_id','voucher_footer_note','voucher_signature_receiver','voucher_signature_accountant','voucher_signature_manager'] as $k)set_setting($k,$_POST[$k]??'');
        foreach(['voucher_show_company_info','voucher_show_lines','voucher_show_signatures','voucher_show_print_user'] as $k)set_setting($k,isset($_POST[$k])?'1':'0');
        $tab='vouchers';
    }elseif($sec==='sys_notifications'){
        set_setting('system_center_enabled',isset($_POST['system_center_enabled'])?'1':'0');
        set_setting('browser_leave_only',isset($_POST['browser_leave_only'])?'1':'0');
        $tab='notifications';
    }
    flash('تم حفظ الإعدادات');
    go('company_settings',['tab'=>$tab]);
}
function act_license_activate(){verify();$u=$_POST['company_user']??'';$p=$_POST['company_pass']??'';if(!company_auth_ok_v45($u,$p)){$a=(int)setting('license_attempts','0')+1;set_setting('license_attempts',$a);if($a>=5){set_setting('license_screen_locked','1');set_setting('license_locked_reason','تم قفل شاشة الترخيص بسبب إدخال بيانات الشركة خطأ أكثر من 5 مرات.');}flash('بيانات الشركة غير صحيحة. المحاولة رقم '.$a.' من 5','err');go('company_settings',['tab'=>'license']);}$type=$_POST['license_type']??'monthly';$end=license_end_for_v45($type,(int)($_POST['qty']??1));if(!$end){flash('لا يمكن أن تتجاوز مدة الترخيص نهاية السنة الحالية. اختر مدة أقل.','err');go('company_settings',['tab'=>'license']);}set_setting('license_status','active');set_setting('license_type',$type);set_setting('license_start',now());set_setting('license_end',$end);set_setting('license_attempts','0');set_setting('license_screen_locked','0');set_setting('license_locked_reason','');set_setting('branches_enabled',isset($_POST['branches_enabled'])?'1':'0');activity_log('license.activate','تفعيل/تغيير الترخيص','الترخيص','license','',$type,'تاريخ الانتهاء: '.$end,'ناجح','حساس');flash('تم تفعيل الترخيص بنجاح إلى '.$end);go('company_settings',['tab'=>'license']);}
function act_license_unlock(){act_license_activate();}


function page_trial_balance(){
    $year=date('Y');$from=$_GET['from']??($year.'-01-01');$to=$_GET['to']??($year.'-12-31');$selected=report_selected_currency_ids('cur');
    $typeRows=[];foreach(['أصول','خصوم','حقوق ملكية','إيرادات','مصروفات','عميل','مورد','مكتب مخلص','بنك','صندوق','وكيل','موظف','عام'] as $x)$typeRows[]=['id'=>$x,'name'=>$x];
    $levelRows=[['id'=>'رئيسي','name'=>'رئيسي'],['id'=>'نهائي','name'=>'نهائي']];
    $showRows=[['id'=>'movement_balance','name'=>'ذات حركة أو رصيد'],['id'=>'movement','name'=>'ذات حركة فقط'],['id'=>'balance','name'=>'ذات رصيد فقط'],['id'=>'all','name'=>'كل الحسابات']];
    $types=report_multi_values('type',$typeRows);$levels=report_multi_values('level',$levelRows);$shows=report_multi_values('show',$showRows);$search=trim($_GET['q']??'');
    $accounts=q('SELECT id,account_no,name,type,parent_id,nature FROM accounts WHERE is_active=1 AND (branch_id IS NULL OR branch_id=0 OR branch_id=?) ORDER BY account_no,name',[branch_id()])->fetchAll();
    $ledger=[];$actualTot=[];$entries=0;$in=implode(',',array_fill(0,count($selected),'?'));
    foreach(q('SELECT account_id,currency_id,DATE(entry_date) d,COALESCE(debit,0) debit,COALESCE(credit,0) credit FROM ledger_entries WHERE branch_id=? AND currency_id IN ('.$in.')',array_merge([branch_id()],$selected))->fetchAll() as $l){$aid=(int)$l['account_id'];$cid=(int)$l['currency_id'];if(!isset($ledger[$aid][$cid]))$ledger[$aid][$cid]=['od'=>0,'oc'=>0,'pd'=>0,'pc'=>0,'count'=>0,'last'=>''];if(!isset($actualTot[$cid]))$actualTot[$cid]=['od'=>0,'oc'=>0,'pd'=>0,'pc'=>0,'cd'=>0,'cc'=>0]; if($l['d']<$from){$ledger[$aid][$cid]['od']+=(float)$l['debit'];$ledger[$aid][$cid]['oc']+=(float)$l['credit'];$actualTot[$cid]['od']+=(float)$l['debit'];$actualTot[$cid]['oc']+=(float)$l['credit'];}elseif($l['d']<=$to){$ledger[$aid][$cid]['pd']+=(float)$l['debit'];$ledger[$aid][$cid]['pc']+=(float)$l['credit'];$ledger[$aid][$cid]['count']++;$actualTot[$cid]['pd']+=(float)$l['debit'];$actualTot[$cid]['pc']+=(float)$l['credit'];$entries++; if($l['d']>$ledger[$aid][$cid]['last'])$ledger[$aid][$cid]['last']=$l['d'];}}
    foreach($selected as $cid){$open=($actualTot[$cid]['od']??0)-($actualTot[$cid]['oc']??0);$close=$open+($actualTot[$cid]['pd']??0)-($actualTot[$cid]['pc']??0);$actualTot[$cid]['cd']=$close>0?$close:0;$actualTot[$cid]['cc']=$close<0?abs($close):0;}
    $parentMap=[];$hasChild=[];foreach($accounts as $x){$parentMap[(int)$x['id']]=(int)($x['parent_id']??0);$p=(int)($x['parent_id']??0);if($p)$hasChild[$p]=1;}
    $directLedger=$ledger;foreach($directLedger as $aid=>$byCur){$p=$parentMap[(int)$aid]??0;while($p){foreach($byCur as $cid=>$m){if(!isset($ledger[$p][$cid]))$ledger[$p][$cid]=['od'=>0,'oc'=>0,'pd'=>0,'pc'=>0,'count'=>0,'last'=>''];foreach(['od','oc','pd','pc','count'] as $k)$ledger[$p][$cid][$k]+=($m[$k]??0);if(($m['last']??'')>$ledger[$p][$cid]['last'])$ledger[$p][$cid]['last']=$m['last'];}$p=$parentMap[$p]??0;}}
    $rows=[];$tot=$actualTot;
    foreach($accounts as $a){if(!in_array((string)$a['type'],$types,true))continue; $lv=isset($hasChild[(int)$a['id']])?'رئيسي':'نهائي'; if(!in_array($lv,$levels,true))continue; foreach($selected as $cid){$m=$ledger[(int)$a['id']][$cid]??['od'=>0,'oc'=>0,'pd'=>0,'pc'=>0,'count'=>0,'last'=>''];$open=$m['od']-$m['oc'];$close=$open+$m['pd']-$m['pc'];$hasMovement=abs($m['pd'])>0.001||abs($m['pc'])>0.001;$hasBalance=abs($close)>0.001||abs($open)>0.001;$okShow=(in_array('all',$shows,true)|| (in_array('movement_balance',$shows,true)&&($hasMovement||$hasBalance)) || (in_array('movement',$shows,true)&&$hasMovement) || (in_array('balance',$shows,true)&&$hasBalance));if(!$okShow)continue;if($search!=='' && mb_stripos($a['account_no'].' '.$a['name'].' '.$a['type'],$search)===false)continue;$row=['id'=>$a['id'],'no'=>$a['account_no'],'name'=>$a['name'],'type'=>$a['type'],'level'=>$lv,'cid'=>$cid,'od'=>$open>0?$open:0,'oc'=>$open<0?abs($open):0,'pd'=>$m['pd'],'pc'=>$m['pc'],'cd'=>$close>0?$close:0,'cc'=>$close<0?abs($close):0,'count'=>$m['count'],'last'=>$m['last']];$rows[]=$row;}}
    $overallBalanced=true;foreach($selected as $cid){$d=(($tot[$cid]['cd']??0)-($tot[$cid]['cc']??0));if(abs($d)>0.01){$overallBalanced=false;break;}}ob_start();?>
