<div class="report-metrics-v33"><div><b>إجمالي مدين ختامي</b><?=metric_lines($tot,'cd',$selected)?></div><div><b>إجمالي دائن ختامي</b><?=metric_lines($tot,'cc',$selected)?></div><div class="<?=$overallBalanced?'ok':'bad'?>"><b>الفارق حسب العملة</b><?=metric_diff_lines($tot,$selected)?></div><div><b>حالة الميزان</b><span><?=$overallBalanced?'متوازن ✅':'غير متوازن ⚠️'?></span></div><div><b>عدد الحسابات</b><span><?=count($rows)?></span></div><div><b>عدد القيود</b><span><?=$entries?></span></div></div>
