ney($tt['cd']??0)?></th><th><?=money($tt['cc']??0)?></th><th><?=currency_code($cid)?></th><th colspan="2" class="<?=abs(($tt['cd']??0)-($tt['cc']??0))<0.01?'ok-diff':'bad-diff'?>">الفارق: <?=money(($tt['cd']??0)-($tt['cc']??0))?></th></tr></tfoot></table></div><?php endforeach;?></div>
